// ── OTT useReveal hook — fade-and-rise once in view ─────────
// Returns { ref, className }. Apply both to a wrapper element and the
// section glides into place on first scroll-into-view. Honours
// prefers-reduced-motion via the .ott-reveal CSS rules above.
function useReveal({ rootMargin='0px 0px -8% 0px', threshold=0.08 } = {}) {
  const ref = React.useRef(null);
  const [shown, setShown] = React.useState(false);
  React.useEffect(() => {
    const el = ref.current; if (!el || shown) return;
    if (typeof IntersectionObserver === 'undefined') { setShown(true); return; }
    const io = new IntersectionObserver(entries => {
      entries.forEach(e => { if (e.isIntersecting) { setShown(true); io.disconnect(); } });
    }, { root:null, rootMargin, threshold });
    io.observe(el);
    return () => io.disconnect();
  }, [shown, rootMargin, threshold]);
  return { ref, className: `ott-reveal${shown?' is-in':''}` };
}

// Light wrapper — drop around any section to give it a reveal-on-scroll.
// Optional `delay` lets you stagger consecutive sections (in seconds).
function Reveal({ children, delay=0, as:Tag='div', style }) {
  const { ref, className } = useReveal();
  const finalStyle = delay ? { ...style, animationDelay:`${delay}s` } : style;
  return <Tag ref={ref} className={className} style={finalStyle}>{children}</Tag>;
}

// ── THEME CONTEXT & HOOK ──────────────────────────────────────
const ThemeContext = React.createContext({ T: T_DARK, isDark: true, toggleTheme: ()=>{} });

function useAppTheme() {
  return React.useContext(ThemeContext);
}

// Theme provider — wraps the whole app.
// Phase 2+ components can call useAppTheme() to get current T.
// Phase 1 components keep using the global T (no change needed yet).
function ThemeProvider({ children }) {
  const [isDark, setIsDark] = React.useState(() => getStoredTheme() !== 'light');

  // Keep global T in sync so legacy code still works
  T = isDark ? T_DARK : T_LIGHT;

  // Apply theme to DOM immediately on mount
  React.useEffect(() => {
    applyThemeToDom(isDark);
  }, [isDark]);

  function applyThemeToDom(dark) {
    const theme = dark ? T_DARK : T_LIGHT;
    try {
      // CSS variables
      document.documentElement.style.setProperty('--app-bg',   theme.bg);
      document.documentElement.style.setProperty('--app-text', theme.text);
      // Body background + class for CSS overrides
      document.body.style.background = theme.bg;
      document.body.classList.toggle('theme-light', !dark);
      document.body.classList.toggle('theme-dark',   dark);
      // Meta theme-color — Android status bar + browser chrome
      let meta = document.querySelector('meta[name="theme-color"]');
      if (!meta) {
        meta = document.createElement('meta');
        meta.name = 'theme-color';
        document.head.appendChild(meta);
      }
      meta.content = theme.bg2; // white on light, navy on dark
    } catch (e) {}
  }

  function toggleTheme() {
    const next = !isDark;
    setIsDark(next);
    T = next ? T_DARK : T_LIGHT;
    try { window.localStorage?.setItem('localaitv_theme', next ? 'dark' : 'light'); } catch (e) {}
    applyThemeToDom(next);
  }

  const value = React.useMemo(() => ({
    T: isDark ? T_DARK : T_LIGHT,
    isDark,
    toggleTheme,
  }), [isDark]);

  return (
    <ThemeContext.Provider value={value}>
      {children}
    </ThemeContext.Provider>
  );
}

