// ── PROMO BANNER — continuously scrolling promotional banner ─────
// Shows birthday/marriage/wishes upload CTA with register link
// Slides left endlessly (duplicated content for seamless loop)
function PromoBanner({ onNavigate }) {
  const { T } = useAppTheme();

  // Each card = one promo slide
  const SLIDES = [
    {
      emoji:   '🎂',
      gradient: ['#7B1FA2', '#AB47BC'],
      titleEn: 'Celebrate Birthdays',
      titleTe: 'పుట్టినరోజు శుభాకాంక్షలు',
      descTe:  'మీ ప్రియమైన వారి పుట్టినరోజు మా ఛానెల్‌లో ప్రసారం చేయండి',
      cta:     'Register Free →',
      action:  'register',
    },
    {
      emoji:   '💍',
      gradient: ['#C2185B', '#E91E63'],
      titleEn: 'Wedding Announcements',
      titleTe: 'పెళ్ళి శుభాకాంక్షలు',
      descTe:  'మీ వివాహ శుభవేళ స్థానిక ప్రేక్షకులకు తెలియజేయండి',
      cta:     'Register Free →',
      action:  'register',
    },
    {
      emoji:   '📺',
      gradient: ['#1565C0', '#1976D2'],
      titleEn: 'Become a Reporter',
      titleTe: 'విలేకరిగా చేరండి',
      descTe:  'మీ ప్రాంత వార్తలు అప్‌లోడ్ చేసి లక్షల మందికి చేరండి',
      cta:     'Register Free →',
      action:  'register',
    },
    {
      emoji:   '📢',
      gradient: ['#E65100', '#F57C00'],
      titleEn: 'Advertise Your Business',
      titleTe: 'మీ వ్యాపారాన్ని ప్రచారం చేయండి',
      descTe:  'స్థానిక ప్రేక్షకులకు మీ ఉత్పత్తులు, సేవలు తెలియజేయండి',
      cta:     'Register Free →',
      action:  'register',
    },
    {
      emoji:   '🌟',
      gradient: ['#2E7D32', '#388E3C'],
      titleEn: 'Join LocalAI TV',
      titleTe: 'LocalAI TV లో చేరండి',
      descTe:  'ఇప్పుడే నమోదు చేసుకుని మీ నియోజకవర్గ వార్తలు పొందండి',
      cta:     'Register Now →',
      action:  'register',
      highlight: true,
    },
  ];

  // Duplicate for seamless infinite loop
  const ALL = [...SLIDES, ...SLIDES];

  return (
    <div style={{
      background: T.isDark ? T.bg2 : '#FFF',
      borderTop:  `1px solid ${T.border}`,
      borderBottom:`1px solid ${T.border}`,
      overflow: 'hidden',
      position: 'relative',
    }}>
      {/* Scrolling track — CSS animation scrolls left forever */}
      <div style={{
        display: 'flex',
        gap: 10,
        padding: '12px 0 12px 12px',
        animation: 'scrollBanner 28s linear infinite',
        width: 'max-content',
      }}>
        {ALL.map((s, i) => (
          <div
            key={i}
            onClick={() => onNavigate(s.action)}
            style={{
              flexShrink: 0,
              width: 240,
              borderRadius: 14,
              overflow: 'hidden',
              cursor: 'pointer',
              background: `linear-gradient(135deg,${s.gradient[0]},${s.gradient[1]})`,
              boxShadow: `0 4px 16px ${s.gradient[0]}44`,
              display: 'flex',
              flexDirection: 'column',
              position: 'relative',
            }}
          >
            {/* Background emoji watermark */}
            <div style={{
              position: 'absolute', top: -8, right: -4,
              fontSize: 72, opacity: 0.15, pointerEvents: 'none',
              lineHeight: 1,
            }}>{s.emoji}</div>

            {/* Card content */}
            <div style={{padding:'12px 14px 10px', position:'relative'}}>
              {/* Top row: emoji + english title */}
              <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:6}}>
                <span style={{fontSize:24}}>{s.emoji}</span>
                <div>
                  <div style={{
                    fontFamily:"'Barlow Condensed',sans-serif",
                    fontWeight:800, fontSize:14,
                    color:'white', letterSpacing:0.5, lineHeight:1.1,
                  }}>{s.titleEn}</div>
                  {s.highlight && (
                    <div style={{
                      display:'inline-block',
                      background:'rgba(255,255,255,0.25)',
                      color:'white', fontSize:7, fontWeight:800,
                      padding:'1px 6px', borderRadius:4,
                      letterSpacing:1, marginTop:2,
                    }}>FREE</div>
                  )}
                </div>
              </div>

              {/* Telugu description */}
              <div style={{
                fontFamily:"'Noto Sans Telugu',sans-serif",
                fontSize:11, fontWeight:500,
                color:'rgba(255,255,255,0.9)',
                lineHeight:1.5, marginBottom:10,
              }}>{s.descTe}</div>

              {/* CTA button */}
              <div style={{
                display:'inline-flex', alignItems:'center', gap:5,
                background:'rgba(255,255,255,0.22)',
                borderRadius:20, padding:'5px 12px',
                fontFamily:"'Barlow Condensed',sans-serif",
                fontWeight:700, fontSize:11, color:'white',
                letterSpacing:0.5,
                border:'1px solid rgba(255,255,255,0.35)',
              }}>{s.cta}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Left/right fade masks for clean edge effect */}
      <div style={{
        position:'absolute', top:0, left:0, bottom:0, width:24,
        background:`linear-gradient(90deg,${T.isDark?T.bg2:'#FFF'},transparent)`,
        pointerEvents:'none', zIndex:2,
      }}/>
      <div style={{
        position:'absolute', top:0, right:0, bottom:0, width:24,
        background:`linear-gradient(270deg,${T.isDark?T.bg2:'#FFF'},transparent)`,
        pointerEvents:'none', zIndex:2,
      }}/>

      {/* Bottom strip — register CTA */}
      <div style={{
        borderTop:`1px solid ${T.border}`,
        padding:'8px 16px',
        display:'flex', alignItems:'center', justifyContent:'space-between',
        background: T.isDark ? 'rgba(208,2,27,0.06)' : 'rgba(208,2,27,0.04)',
      }}>
        <div style={{fontFamily:"'Noto Sans Telugu',sans-serif",fontSize:11,color:T.textMuted,lineHeight:1.65}}>
          మీ వార్తలు, శుభాకాంక్షలు ప్రసారం చేయండి
        </div>
        <button
          onClick={() => onNavigate('register')}
          style={{
            background:`linear-gradient(135deg,${T.red},#7A0010)`,
            color:'white', border:'none', borderRadius:20,
            padding:'6px 14px',
            fontFamily:"'Barlow Condensed',sans-serif",
            fontWeight:800, fontSize:11, letterSpacing:0.8,
            cursor:'pointer', flexShrink:0,
            boxShadow:`0 3px 10px ${T.red}44`,
            whiteSpace:'nowrap',
          }}>
          📲 Register Now
        </button>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   SECTION ACCENT BAR — Phase 5.5: system propagation primitive
   ───────────────────────────────────────────────────────────────────
   3w × 22h red bar with soft glow. Originally inline in Classifieds
   (Phase 1). Extracted here so all home-page section headers share
   the same identity primitive — tuning happens in one place.
   ═══════════════════════════════════════════════════════════════════ */
function SectionAccentBar() {
  // Adaptive shadow: in light mode, a subtle dark underbase anchors the bar
  // against bright surfaces. Same red, same glow, same dimensions — only
  // the perceived authority is normalized. Mohan: "goal is consistency of
  // perceived authority, not consistency of raw dimensions."
  const { T } = useAppTheme();
  const isLight = !T.isDark;
  return (
    <div style={{
      width:3, height:22, borderRadius:2,
      background:OTT.color.red,
      boxShadow: isLight
        ? `0 0 16px rgba(225,29,72,0.32), 0 1px 3px rgba(0,0,0,0.14)`
        : `0 0 14px ${OTT.color.redSoft}`,
      flexShrink:0,
    }}/>
  );
}

// ── SHORT NEWS SECTION COMPONENT (with auto-scroll) ─────────
function ShortNewsSection({ channel }) {
  const { T } = useAppTheme();
  const [openIdx,    setOpenIdx]    = useState(null);
  const [showFeed,   setShowFeed]   = useState(false);
  const scrollRef  = useRef(null);
  const [paused, setPaused] = useState(false);

  // Auto-scroll strip
  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    const iv = setInterval(() => {
      if (!el || paused) return;
      const half = el.scrollWidth / 2;
      if (el.scrollLeft >= half) el.scrollLeft -= half;
      else el.scrollLeft += 1;
    }, 30);
    return () => clearInterval(iv);
  }, [paused]);

  const items = [...SHORT_NEWS, ...SHORT_NEWS];
  const total = SHORT_NEWS.length;

  return (
    <div style={{ background:T.bg }}>
      {/* Header — Phase 5.5: shared accent bar primitive */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between',
        padding:'14px 16px 10px', gap:10 }}>
        <div style={{ display:'flex', alignItems:'center', gap:9, minWidth:0 }}>
          <SectionAccentBar/>
          <div style={{ display:'flex', alignItems:'baseline', gap:6, minWidth:0 }}>
            <span style={{ fontFamily:"'Noto Sans Telugu',sans-serif", fontWeight:800,
              fontSize:16, color:T.text }}>
              మన {channel ? channel.name : 'కర్నూలు'}
            </span>
            <span style={{
              fontFamily:"'Barlow Condensed',sans-serif", fontWeight:900,
              fontSize:18, letterSpacing:1,
              background:'linear-gradient(135deg,#0D1B5C,#1A3FCC)', // dark navy → cobalt blue
              WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text',
            }}>Shorts</span>
          </div>
        </div>
        <span onClick={() => setOpenIdx(0)}
          style={{ fontSize:11, color:T.red, fontWeight:600, cursor:'pointer', flexShrink:0 }}>See all →</span>
      </div>

      {/* Cards — YouTube Shorts aspect ratio 9:16 ≈ width:108 height:192 */}
      <div
        ref={scrollRef}
        onTouchStart={() => setPaused(true)}
        onTouchEnd={() => setTimeout(() => setPaused(false), 3000)}
        style={{ display:'flex', gap:8, padding:'0 16px 14px',
          overflowX:'auto', scrollbarWidth:'none', WebkitOverflowScrolling:'touch' }}
      >
        {items.map((s, i) => (
          <div key={i} onClick={() => {
              // Viewer renders items sorted by uploadedAt (newest first).
              // To open the SAME clip the user tapped, look up its position
              // in the sorted feed by id and pass that as the initial index.
              const sortedFeed = sortShortsForFeed(SHORT_NEWS);
              const realIdx = sortedFeed.findIndex(x => x.id === s.id);
              setOpenIdx(realIdx >= 0 ? realIdx : 0);
            }}
            style={{ flexShrink:0, width:108, cursor:'pointer', position:'relative' }}>
            {/* Clean 9:16 thumbnail — no text overlays, no dark gradient */}
            <div style={{ width:108, height:192, borderRadius:10, overflow:'hidden',
              background:'#111', position:'relative' }}>
              <img
                src={s.img}
                alt={s.titleEn}
                style={{ width:'100%', height:'100%', objectFit:'cover' }}
                onError={e => { e.target.src = `https://img.youtube.com/vi/${s.ytId}/hqdefault.jpg`; }}
              />
              {/* Tiny LIVE indicator — pulsing red dot only, no text */}
              {s.live && (
                <div style={{ position:'absolute', top:7, left:7,
                  width:9, height:9, borderRadius:'50%',
                  background:'#D0021B',
                  boxShadow:'0 0 0 2px rgba(255,255,255,0.9), 0 0 0 3.5px rgba(208,2,27,0.35)',
                  animation:'blink 1s infinite' }}/>
              )}
            </div>
            {/* Title below thumbnail (moved from on-image overlay) */}
            <div style={{ marginTop:6, fontSize:10.5, fontWeight:700, lineHeight:1.3,
              color:T.text, fontFamily:"'Noto Sans Telugu',sans-serif",
              display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical',
              overflow:'hidden' }}>
              {s.titleTe}
            </div>
          </div>
        ))}
      </div>

      {/* Unified Feed Viewer — Shorts */}
      {openIdx !== null && (
        <KurnoolShortsScreen
          rawItems={SHORT_NEWS}
          initialIdx={openIdx || 0}
          onClose={() => setOpenIdx(null)}
        />
      )}
    </div>
  );
}

// ── KURNOOL PUBLIC VOICE SECTION — auto-scroll + manual swipe ─────
// Native horizontal scroller (so finger-swipe and momentum work normally),
// with the auto-scroll just nudging scrollLeft a few pixels per frame when
// the user is idle. The items are TRIPLED and we start in the middle copy;
// when scrollLeft drifts into the outer buffer zones we shift it by exactly
// one copy-width — because copy-N is identical to copy-N±1, that shift is
// pixel-for-pixel invisible. So the rail is genuinely endless in both
// directions and the user can swipe freely at any time.
/* ═══════════════════════════════════════════════════════════════════════
   Public Voice → Shorts-shape mapper
   ───────────────────────────────────────────────────────────────────────
   Public Voice items are user-uploaded videos. To render them in the
   Mana Kurnool Shorts viewer (KurnoolShortsScreen), we transform each
   pv item into the SHORT_NEWS shape. ONLY uploaded form data flows
   through — no static/demo channel branding, no fake view counts.
   The fullText is stripped of the trailing "📍 location · 📞 phone"
   line (already captured in dedicated fields).
   ═══════════════════════════════════════════════════════════════════════ */
function publicVoiceToShortShape(pv) {
  // Strip the trailing "\n\n📍 ..." block from desc — that info already
  // lives in pv.location / pv.phone and is rendered separately
  const cleanDesc = (pv.desc || '').split(/\n\n📍/)[0].trim();
  return {
    id:          pv.id,
    ytId:        pv.ytId,
    orientation: pv.orientation || 'vertical',
    titleTe:     pv.title || '',
    titleEn:     '',                          // Public Voice is Telugu-only
    fullText:    cleanDesc,
    channel:     'పబ్లిక్ వాయిస్',             // generic section label, not a TV channel
    reporter:    pv.uploaderName || '',
    profilePhoto: pv.uploaderPhoto || '',
    location:    pv.location || '',
    category:    'Public Voice',
    views:       '',                          // not tracked for citizen uploads
    duration:    pv.duration || null,
    live:        false,
    uploadDate:  pv.date || '',
    uploadTime:  pv.time || '',
    img:         (pv.images && pv.images[0]) || (pv.ytId ? `https://img.youtube.com/vi/${pv.ytId}/maxresdefault.jpg` : ''),
    bg:          ['#0a0010','#3a0030'],
    uploadedAt:  pv.uploadedAt ? new Date(pv.uploadedAt) : new Date(),
  };
}

function PublicVoiceSection({ onNavigate, channel }) {
  const { T } = useAppTheme();
  const scrollerRef    = useRef(null);
  const touchingRef    = useRef(false);
  const lastTouchEndAt = useRef(0);
  const lastTickAt     = useRef(0);
  const initialisedRef = useRef(false);

  const items = CLASSIFIEDS.filter(c => c.cat === 'Public Voice');
  if (items.length === 0) return null;

  const CARD_W = 116;                  // 108 + marginRight:8
  const cycleW = items.length * CARD_W;
  const looped = [...items, ...items, ...items];   // 3 copies

  function openCard(item) {
    // Route Public Voice into the Mana Kurnool Shorts viewer
    // (KurnoolShortsScreen) instead of the image-based classifieds
    // viewer. The mapper publicVoiceToShortShape transforms each pv
    // item to the SHORT_NEWS shape so the viewer renders identically
    // to "మన కర్నూలు షార్ట్స్".
    if (typeof window !== 'undefined' && item && item.id) {
      window.__publicVoiceStartId = item.id;
    }
    onNavigate && onNavigate('publicvoicefeed');
  }

  useEffect(() => {
    const el = scrollerRef.current;
    if (!el) return;
    // Park scroll position in the middle copy on first mount so the user
    // can freely swipe left and right by a whole copy before we wrap.
    if (!initialisedRef.current) {
      el.scrollLeft = cycleW;
      initialisedRef.current = true;
    }

    let raf;
    const SPEED = 28; // px / sec — calm reels-like pace
    const tick = (t) => {
      if (!el) { raf = requestAnimationFrame(tick); return; }
      if (lastTickAt.current === 0) lastTickAt.current = t;
      const dt = Math.min(0.1, (t - lastTickAt.current) / 1000);
      lastTickAt.current = t;

      // Auto-nudge only when the user is fully idle (touch released for >1s
      // so native momentum has finished). Otherwise let native scroll run.
      const idleMs = performance.now() - lastTouchEndAt.current;
      if (!touchingRef.current && idleMs > 1000) {
        el.scrollLeft += SPEED * dt;
      }

      // Buffer-zone wrap: when scrollLeft drifts past the middle copy in
      // either direction, snap by exactly cycleW. Visually identical pixels
      // (because the copies are duplicates), so the snap is invisible — and
      // it never happens near where the user's finger is right now.
      if (el.scrollLeft >= 2 * cycleW)      el.scrollLeft -= cycleW;
      else if (el.scrollLeft < cycleW * 0.5) el.scrollLeft += cycleW;

      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [cycleW]);

  // Touch / mouse — purely for tracking idle state; native scroll handles motion.
  const onTouchStart = () => { touchingRef.current = true; };
  const onTouchEnd   = () => { touchingRef.current = false; lastTouchEndAt.current = performance.now(); };

  return (
    <div style={{ background:T.bg }}>
      {/* Header — Phase 5.5: shared accent bar primitive */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between',
        padding:'14px 16px 10px', gap:10 }}>
        <div style={{ display:'flex', alignItems:'center', gap:9, minWidth:0 }}>
          <SectionAccentBar/>
          <div style={{ display:'flex', alignItems:'baseline', gap:6, minWidth:0 }}>
            <span style={{ fontFamily:"'Noto Sans Telugu',sans-serif", fontWeight:800,
              fontSize:16, color:T.text }}>
              {channel ? channel.name : 'కర్నూలు'}
            </span>
            <span style={{
              fontFamily:"'Noto Sans Telugu',sans-serif", fontWeight:900,
              fontSize:17, letterSpacing:0.3,
              background:'linear-gradient(135deg,#DC2626,#F97316)',
              WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text',
            }}>పబ్లిక్ వాయిస్</span>
          </div>
        </div>
        <span onClick={openCard}
          style={{ fontSize:11, color:T.red, fontWeight:600, cursor:'pointer', flexShrink:0 }}>See all →</span>
      </div>

      {/* Native horizontal scroller. Auto-nudge + manual swipe coexist. */}
      <div
        ref={scrollerRef}
        onTouchStart={onTouchStart}
        onTouchEnd={onTouchEnd}
        onTouchCancel={onTouchEnd}
        onMouseDown={onTouchStart}
        onMouseUp={onTouchEnd}
        onMouseLeave={onTouchEnd}
        style={{
          display:'flex',
          padding:'0 16px 14px',
          overflowX:'auto',
          overflowY:'hidden',
          scrollbarWidth:'none',
          msOverflowStyle:'none',
          WebkitOverflowScrolling:'touch',
          overscrollBehaviorX:'contain',
        }}>
        {looped.map((s, i) => (
          <div key={`pv-${i}`} onClick={() => openCard(s)}
            style={{ flexShrink:0, width:108, marginRight:8, cursor:'pointer', position:'relative' }}>
            {/* Clean 9:16 thumbnail — prefer YouTube video thumbnail
                when ytId is present so the rail visually signals
                "this is a video" rather than a still photo */}
            <div style={{ width:108, height:192, borderRadius:10, overflow:'hidden',
              background:'#111', position:'relative' }}>
              <img
                src={s.ytId
                  ? `https://img.youtube.com/vi/${s.ytId}/maxresdefault.jpg`
                  : (s.images && s.images[0])}
                alt={s.title}
                draggable={false}
                style={{ width:'100%', height:'100%', objectFit:'cover',
                  pointerEvents:'none' /* let touch go to the scroller */ }}
                onError={e => {
                  // Fallback chain: hqdefault → images[0] → fade out
                  if (s.ytId && !e.target.dataset.fellback) {
                    e.target.dataset.fellback = '1';
                    e.target.src = `https://img.youtube.com/vi/${s.ytId}/hqdefault.jpg`;
                  } else if (s.images && s.images[0] && e.target.src !== s.images[0]) {
                    e.target.src = s.images[0];
                  } else {
                    e.target.style.opacity='0.25';
                  }
                }}
              />
              {/* Play icon overlay — quiet white circle with dark
                  triangle, signals video without shouting */}
              {s.ytId && (
                <div style={{ position:'absolute', inset:0,
                  display:'flex', alignItems:'center', justifyContent:'center',
                  pointerEvents:'none' }}>
                  <div style={{ width:32, height:32, borderRadius:'50%',
                    background:'rgba(255,255,255,0.88)',
                    display:'flex', alignItems:'center', justifyContent:'center',
                    boxShadow:'0 2px 8px rgba(0,0,0,0.35)' }}>
                    <div style={{ width:0, height:0, marginLeft:2,
                      borderTop:'6px solid transparent',
                      borderBottom:'6px solid transparent',
                      borderLeft:'9px solid #1A237E' }}/>
                  </div>
                </div>
              )}
            </div>
            {/* Issue name below */}
            <div style={{ marginTop:6, fontSize:10.5, fontWeight:700, lineHeight:1.3,
              color:T.text, fontFamily:"'Noto Sans Telugu',sans-serif",
              display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical',
              overflow:'hidden' }}>
              {s.title}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── CLASSIFIEDS SECTION — fully rebuilt ──────────────────────
function ClassifiedsSection({ onNavigate, constituency, channel }) {
  const { T } = useAppTheme();
  const [cat,      setCat]      = useState('All');
  const [selected, setSelected] = useState(null);
  const [selIdx,   setSelIdx]   = useState(0);
  const scrollRef = useRef(null);
  const [paused, setPaused] = useState(false);

  const { data: liveClassifieds } = useAPI(
    () => apiCall(`/classifieds?constituency=${encodeURIComponent(constituency)}&limit=30`).then(d => d.items || d),
    CLASSIFIEDS, [constituency]
  );
  const all = (Array.isArray(liveClassifieds) && liveClassifieds.length > 0) ? liveClassifieds : CLASSIFIEDS;

  // Randomly shuffle for display on home page — memoised so it doesn't re-shuffle on every re-render
  const shuffled = useMemo(() => [...all].sort(() => Math.random() - 0.5), [all]);
  const filtered = cat === 'All' ? shuffled : all.filter(c => c.cat === cat);

  // Auto-scroll the strip continuously, like Mana Kurnool Shorts.
  // We render the filtered items TWICE in a row, then loop scrollLeft from 0 → half → 0,
  // so the transition is seamless (no jump when looping).
  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    const iv = setInterval(() => {
      if (!el || paused) return;
      const half = el.scrollWidth / 2;
      if (el.scrollLeft >= half) el.scrollLeft -= half;
      else el.scrollLeft += 1;
    }, 30);
    return () => clearInterval(iv);
  }, [paused, cat, filtered.length]);

  // Open the tapped classified in the App-level classifieds detail page
  // (not an inline overlay). Per Mohan's request: clicking any Kurnool
  // Local thumbnail should navigate to a separate page rather than
  // rendering inside this section. Category + item id are stashed in
  // window flags so the route handler can land on the exact item.
  function openItem(item) {
    if (typeof window !== 'undefined') {
      window.__classifiedsStartCat    = cat;
      window.__classifiedsStartItemId = item && item.id;
    }
    onNavigate && onNavigate('classifiedsfeed');
  }

  return (
    <>
      <div style={{background:T.bg}}>
        {/* ── Header — OTT premium typography hierarchy with red accent bar ── */}
        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'18px 16px 10px',gap:10}}>
          <div style={{display:'flex',alignItems:'center',gap:9,minWidth:0}}>
            {/* Section accent bar — Phase 5.5 shared primitive */}
            <SectionAccentBar/>
            <div style={{display:'flex',alignItems:'baseline',gap:6,minWidth:0}}>
              <span style={{
                fontFamily:OTT.type.te.font, fontWeight:800, fontSize:18,
                color:T.text, letterSpacing:0.2,
                whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis',
              }}>{channel?channel.name:'కర్నూలు'}</span>
              <span style={{
                fontFamily:OTT.type.display.font, fontWeight:900, fontSize:20, letterSpacing:1.2,
                background:'linear-gradient(135deg,#00ACC1,#26C6DA)',
                WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text',
              }}>LOCAL</span>
            </div>
          </div>
          <button onClick={()=>onNavigate&&onNavigate('classifiedsfeed')}
            className="ott-press"
            style={{flexShrink:0, background:'transparent',
              border:`1px solid ${T.border}`, borderRadius:OTT.radius.pill,
              padding:'5px 11px', fontSize:10, color:T.textMuted, fontWeight:700,
              cursor:'pointer', letterSpacing:0.6,
              fontFamily:OTT.type.mono.font, textTransform:'uppercase',
            }}>
            See all  ›
          </button>
        </div>

        {/* ── Category pills with hover highlight ──
            paddingTop:6 leaves room for the hover lift so the top border doesn't get clipped. */}
        <div style={{display:'flex',gap:6,padding:'6px 16px 10px',overflowX:'auto',overflowY:'visible',scrollbarWidth:'none'}}>
          {CL_CATS.map(c=>(
            <button key={c} onClick={()=>setCat(c)}
              onMouseEnter={e=>{
                if (cat===c) return;
                e.currentTarget.style.transform='translateY(-2px) scale(1.04)';
                e.currentTarget.style.boxShadow='0 4px 14px rgba(43,127,255,0.3)';
                e.currentTarget.style.borderColor='rgba(43,127,255,0.55)';
                e.currentTarget.style.background='rgba(43,127,255,0.10)';
              }}
              onMouseLeave={e=>{
                e.currentTarget.style.transform='translateY(0) scale(1)';
                e.currentTarget.style.boxShadow= cat===c?'0 2px 10px rgba(43,127,255,0.3)':'none';
                e.currentTarget.style.borderColor= cat===c?'#2B7FFF':T.border;
                e.currentTarget.style.background= cat===c?'#2B7FFF':T.bg3;
              }}
              style={{
              display:'flex',alignItems:'center',gap:5,flexShrink:0,
              background: cat===c ? '#2B7FFF' : T.bg3,
              border:`1.5px solid ${cat===c?'#2B7FFF':T.border}`,
              borderRadius:14,padding:'5px 11px',cursor:'pointer',
              transition:'all 0.2s cubic-bezier(0.22,1,0.36,1)',
              boxShadow: cat===c?'0 2px 10px rgba(43,127,255,0.3)':'none',
            }}>
              <span style={{fontSize:13}}>{CL_CAT_EMOJI[c]}</span>
              <div>
                <div style={{fontSize:10,fontWeight:700,lineHeight:1.1,
                  color:cat===c?'white':T.text,
                  fontFamily:"'Barlow Condensed',sans-serif",letterSpacing:0.3}}>{c}</div>
                <div style={{fontSize:8,lineHeight:1,marginTop:1,
                  color:cat===c?'rgba(255,255,255,0.75)':T.textMuted,
                  fontFamily:"'Noto Sans Telugu',sans-serif"}}>{CL_CATS_TE[c]||c}</div>
              </div>
            </button>
          ))}
        </div>

        {/* ── Cards — continuous auto-scroll loop (doubled list) ── */}
        <div
          ref={scrollRef}
          onTouchStart={() => setPaused(true)}
          onTouchEnd={() => setTimeout(() => setPaused(false), 3000)}
          style={{display:'flex',gap:10,padding:'0 16px 14px',overflowX:'auto',scrollbarWidth:'none',WebkitOverflowScrolling:'touch'}}>
          {[...filtered, ...filtered].map((cl,i)=>(
            <div key={cl.id+'-'+i} onClick={()=>openItem(cl)}
              style={{flexShrink:0,width:155,borderRadius:14,overflow:'hidden',
                border:`1px solid ${T.border}`,cursor:'pointer',
                background:T.bg2,
                boxShadow:T.isDark?'none':`0 2px 10px ${T.shadow}`,
                transition:'transform 0.15s',
              }}
              onTouchStart={e=>e.currentTarget.style.transform='scale(0.97)'}
              onTouchEnd={e=>e.currentTarget.style.transform='scale(1)'}
            >
              {/* Real category thumbnail image */}
              <div style={{width:'100%',height:100,position:'relative',overflow:'hidden',
                background:T.bg3}}>
                <img
                  src={CL_CAT_IMG[cl.cat] || CL_CAT_IMG['Events']}
                  alt={cl.cat}
                  style={{width:'100%',height:'100%',objectFit:'cover',display:'block'}}
                  onError={e=>{e.target.style.display='none';}}
                />
                {/* Light gradient at bottom for text */}
                <div style={{position:'absolute',bottom:0,left:0,right:0,height:40,
                  background:'linear-gradient(0deg,rgba(0,0,0,0.55),transparent)'}}/>
                {/* Category badge top-left */}
                <div style={{position:'absolute',top:6,left:6,
                  background:'rgba(0,0,0,0.65)',borderRadius:5,
                  padding:'2px 7px',display:'flex',alignItems:'center',gap:3}}>
                  <span style={{fontSize:9}}>{CL_CAT_EMOJI[cl.cat]}</span>
                  <span style={{fontFamily:"'Barlow Condensed',sans-serif",
                    fontSize:8,fontWeight:800,color:'white',letterSpacing:0.5}}>{cl.cat}</span>
                </div>
                {/* Time badge top-right */}
                <div style={{position:'absolute',top:6,right:6,
                  background:'rgba(0,0,0,0.6)',borderRadius:5,padding:'2px 6px'}}>
                  <span style={{fontSize:8,color:'rgba(255,255,255,0.85)'}}>{cl.time}</span>
                </div>
              </div>
              {/* Card body */}
              <div style={{padding:'8px 10px 10px'}}>
                <div style={{fontSize:11,fontWeight:700,lineHeight:1.3,
                  color:T.text,marginBottom:4,
                  display:'-webkit-box',WebkitLineClamp:2,WebkitBoxOrient:'vertical',overflow:'hidden'}}>
                  {cl.title}
                </div>
                <div style={{display:'flex',alignItems:'center',gap:4}}>
                  <span style={{fontSize:8,color:'#2B7FFF'}}>📍 {cl.location.slice(0,12)}</span>
                </div>
              </div>
            </div>
          ))}
          {/* "Post Free Ad" CTA removed per user request — strip now loops continuously */}
        </div>
      </div>

      {/* Inline ClassifiedsFeedScreen overlay removed — tapping a
          thumbnail now navigates to the App-level 'classifiedsfeed'
          route for a clean page transition (per Mohan's request). */}
    </>
  );
}

// ── CLASSIFIEDS FULL SCREEN ───────────────────────────────────
// ── INSTAGRAM-STYLE CLASSIFIEDS FULL-SCREEN VIEWER ────────────
// One classified per screen. Swipe up → next, swipe down → prev.
// Uses CSS scroll-snap for native feel. Opens at tapped item index.
function InstagramClassifiedsViewer({ items, startIndex, onClose, badgeColor }) {
  const { T } = useAppTheme();
  const containerRef = useRef(null);

  // Scroll to the startIndex card on mount
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    // Scroll instantly to the tapped card (no animation on open)
    el.scrollTo({ top: startIndex * window.innerHeight, behavior: 'auto' });
  }, [startIndex]);

  // Derive current visible index from scroll position
  const [currentIdx, setCurrentIdx] = useState(startIndex);
  function handleScroll(e) {
    const idx = Math.round(e.target.scrollTop / window.innerHeight);
    setCurrentIdx(Math.max(0, Math.min(idx, items.length - 1)));
  }

  const cl = items[currentIdx] || items[0];

  // Category gradient backgrounds — each category has its own colour
  const catGradient = {
    Property:    ['#1e3a5f', '#2563eb'],
    Vehicles:    ['#1a3a1a', '#16a34a'],
    Jobs:        ['#3a1a0a', '#ea580c'],
    Electronics: ['#1a1a3a', '#7c3aed'],
    Services:    ['#0a2a2a', '#0891b2'],
    Agri:        ['#1a3a0a', '#15803d'],
    Shops:       ['#2a1a0a', '#b45309'],
    Marriage:    ['#3a0a2a', '#be185d'],
    Wishes:      ['#2a0a3a', '#9333ea'],
    Education:   ['#0a1a3a', '#1d4ed8'],
    Pets:        ['#2a1a0a', '#92400e'],
  };
  const grad = catGradient[cl?.cat] || ['#1a1a2e', '#374151'];

  return (
    <div style={{
      position: 'absolute', inset: 0, zIndex: 100,
      background: '#000',
    }}>
      {/* ── SNAP SCROLL CONTAINER ── */}
      <div
        ref={containerRef}
        onScroll={handleScroll}
        style={{
          width: '100%',
          height: '100%',
          overflowY: 'scroll',
          scrollSnapType: 'y mandatory',
          WebkitOverflowScrolling: 'touch',
          scrollbarWidth: 'none',
        }}
      >
        {items.map((item, idx) => {
          const g = catGradient[item.cat] || ['#1a1a2e', '#374151'];
          return (
            <div
              key={item.id}
              style={{
                width: '100%',
                height: '100%',
                flexShrink: 0,
                scrollSnapAlign: 'start',
                scrollSnapStop: 'always',
                background: `linear-gradient(160deg, ${g[0]} 0%, ${g[1]} 60%, #000 100%)`,
                display: 'flex',
                flexDirection: 'column',
                position: 'relative',
                overflow: 'hidden',
              }}
            >
              {/* Big background emoji watermark */}
              <div style={{
                position: 'absolute',
                top: '15%', right: '-10%',
                fontSize: 200, opacity: 0.07,
                pointerEvents: 'none',
                lineHeight: 1,
                userSelect: 'none',
              }}>{item.emoji}</div>

              {/* Top bar — close + counter */}
              <div style={{
                position: 'absolute', top: 0, left: 0, right: 0,
                padding: '52px 16px 12px',
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                background: 'linear-gradient(180deg,rgba(0,0,0,0.6) 0%,transparent 100%)',
                zIndex: 10,
              }}>
                <button onClick={onClose} style={{
                  width: 36, height: 36, borderRadius: '50%',
                  background: 'rgba(0,0,0,0.5)',
                  border: '1px solid rgba(255,255,255,0.2)',
                  color: 'white', fontSize: 18, cursor: 'pointer',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>←</button>
                <div style={{
                  background: 'rgba(0,0,0,0.5)',
                  border: '1px solid rgba(255,255,255,0.2)',
                  borderRadius: 20, padding: '5px 12px',
                  fontFamily: "'Barlow Condensed',sans-serif",
                  fontWeight: 700, fontSize: 12, color: 'white',
                }}>
                  {idx + 1} / {items.length}
                </div>
                <div style={{width:36}}/>
              </div>

              {/* Scroll hint dots (right side like Instagram) */}
              <div style={{
                position: 'absolute', right: 14,
                top: '50%', transform: 'translateY(-50%)',
                display: 'flex', flexDirection: 'column', gap: 5, zIndex: 10,
              }}>
                {items.slice(Math.max(0,idx-2), Math.min(items.length, idx+3)).map((_, di) => {
                  const absIdx = Math.max(0,idx-2) + di;
                  return (
                    <div key={di} style={{
                      width: absIdx===idx ? 6 : 4,
                      height: absIdx===idx ? 6 : 4,
                      borderRadius: '50%',
                      background: absIdx===idx ? 'white' : 'rgba(255,255,255,0.4)',
                      transition: 'all 0.2s',
                    }}/>
                  );
                })}
              </div>

              {/* Main content — centered */}
              <div style={{
                flex: 1, display: 'flex', flexDirection: 'column',
                justifyContent: 'flex-end',
                padding: '0 20px 28px',
              }}>
                {/* Category badge */}
                <div style={{
                  display: 'inline-flex', alignItems: 'center', gap: 5,
                  background: 'rgba(255,255,255,0.15)',
                  border: '1px solid rgba(255,255,255,0.3)',
                  borderRadius: 20, padding: '4px 12px',
                  marginBottom: 12, alignSelf: 'flex-start',
                  fontFamily: "'Barlow Condensed',sans-serif",
                  fontWeight: 700, fontSize: 11, color: 'white', letterSpacing: 0.5,
                }}>
                  {CL_CAT_EMOJI[item.cat]} {item.cat.toUpperCase()}
                </div>

                {/* Title */}
                <div style={{
                  fontFamily: "'Barlow Condensed',sans-serif",
                  fontWeight: 800, fontSize: 26,
                  color: 'white', lineHeight: 1.15,
                  marginBottom: 10,
                  textShadow: '0 2px 12px rgba(0,0,0,0.5)',
                }}>{item.title}</div>

                {/* Description */}
                <div style={{
                  fontSize: 14, color: 'rgba(255,255,255,0.88)',
                  lineHeight: 1.6, marginBottom: 16,
                  textShadow: '0 1px 6px rgba(0,0,0,0.4)',
                }}>{item.desc}</div>

                {/* Meta row */}
                <div style={{
                  display: 'flex', gap: 14, marginBottom: 20,
                  flexWrap: 'wrap',
                }}>
                  {[
                    { icon: '📍', val: item.location },
                    { icon: '🕐', val: item.time },
                    { icon: '📞', val: item.contact },
                  ].map(m => (
                    <div key={m.icon} style={{
                      display: 'flex', alignItems: 'center', gap: 5,
                      background: 'rgba(0,0,0,0.35)',
                      border: '1px solid rgba(255,255,255,0.15)',
                      borderRadius: 20, padding: '4px 10px',
                      fontSize: 11, color: 'rgba(255,255,255,0.9)',
                      fontWeight: 600,
                    }}>
                      <span style={{fontSize:12}}>{m.icon}</span> {m.val}
                    </div>
                  ))}
                </div>

                {/* Action buttons */}
                <div style={{display: 'flex', gap: 10}}>
                  {!NO_CALL_CATS.includes(item.cat) ? (
                    <>
                      <button
                        onClick={() => window.open(`tel:+91${item.contact.replace(/\s/g,'')}`)}
                        style={{
                          flex: 1,
                          background: 'linear-gradient(135deg,#059669,#047857)',
                          border: 'none', borderRadius: 14,
                          padding: '14px', color: 'white',
                          fontFamily: "'Barlow Condensed',sans-serif",
                          fontWeight: 800, fontSize: 15, cursor: 'pointer',
                          letterSpacing: 0.5,
                          boxShadow: '0 4px 16px rgba(5,150,105,0.4)',
                        }}>
                        📞 Call Now
                      </button>
                      <button
                        onClick={() => window.open(`https://wa.me/91${item.contact.replace(/\s/g,'')}?text=${encodeURIComponent('Hi, I saw your ad on LocalAI TV: '+item.title)}`,'_blank')}
                        style={{
                          flex: 1,
                          background: 'linear-gradient(135deg,#16a34a,#15803d)',
                          border: 'none', borderRadius: 14,
                          padding: '14px', color: 'white',
                          fontFamily: "'Barlow Condensed',sans-serif",
                          fontWeight: 800, fontSize: 15, cursor: 'pointer',
                          letterSpacing: 0.5,
                          boxShadow: '0 4px 16px rgba(22,163,74,0.4)',
                        }}>
                        💬 WhatsApp
                      </button>
                    </>
                  ) : (
                    <button
                      onClick={() => window.open(`https://wa.me/91${item.contact.replace(/\s/g,'')}?text=${encodeURIComponent('Hi, I saw your post on LocalAI TV: '+item.title)}`,'_blank')}
                      style={{
                        flex: 1,
                        background: 'linear-gradient(135deg,#be185d,#9d174d)',
                        border: 'none', borderRadius: 14,
                        padding: '14px', color: 'white',
                        fontFamily: "'Barlow Condensed',sans-serif",
                        fontWeight: 800, fontSize: 15, cursor: 'pointer',
                        boxShadow: '0 4px 16px rgba(190,24,93,0.4)',
                      }}>
                      💕 Send Wishes
                    </button>
                  )}
                </div>

                {/* Swipe hint — only on first card */}
                {idx === startIndex && (
                  <div style={{
                    textAlign: 'center', marginTop: 12,
                    fontSize: 11, color: 'rgba(255,255,255,0.5)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5,
                  }}>
                    <span style={{animation:'bounceUp 1.2s ease-in-out infinite'}}>↑</span>
                    Swipe up for more ads
                    <span style={{animation:'bounceUp 1.2s ease-in-out infinite'}}>↑</span>
                    <style>{`@keyframes bounceUp{0%,100%{transform:translateY(0)}50%{transform:translateY(-4px)}}`}</style>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function ClassifiedsScreen({ onBack, constituency, initialCat }) {
  const { T } = useAppTheme();
  const [cat,        setCat]        = useState(initialCat || 'All');
  const [search,     setSearch]     = useState('');
  const [showPost,   setShowPost]   = useState(false);
  const [igIndex,    setIgIndex]    = useState(null); // null = list view, number = Instagram view

  // Post form state
  const [pTitle,     setPTitle]     = useState('');
  const [pDesc,      setPDesc]      = useState('');
  const [pCat,       setPCat]       = useState('Property');
  const [pContact,   setPContact]   = useState('');
  const [pLocation,  setPLocation]  = useState('');
  const [pSubmitted, setPSubmitted] = useState(false);

  const filtered = CLASSIFIEDS.filter(c =>
    (cat === 'All' || c.cat === cat) &&
    (!search || c.title.toLowerCase().includes(search.toLowerCase()) ||
     c.desc.toLowerCase().includes(search.toLowerCase()) ||
     c.cat.toLowerCase().includes(search.toLowerCase()))
  );

  const badgeColor = (badge) => {
    for (const [k,v] of Object.entries(CL_BADGE_COLOR)) { if (badge === k) return v; }
    if (badge && badge.startsWith('₹')) return '#b45309';
    return '#374151';
  };

  // ── POST AD FORM ──────────────────────────────────────────────
  if (showPost) return (
    <div style={{width:'100%',height:'100%',display:'flex',flexDirection:'column',background:'#f7f8fa'}}>
      <div style={{background:'linear-gradient(135deg,#1e3a8a,#3b82f6)',padding:'48px 18px 20px',flexShrink:0,position:'relative'}}>
        <button onClick={()=>setShowPost(false)} style={{position:'absolute',top:52,left:14,background:'rgba(255,255,255,0.2)',border:'none',borderRadius:8,width:32,height:32,color:'white',fontSize:16,cursor:'pointer'}}>←</button>
        <div style={{textAlign:'center'}}>
          <div style={{fontSize:36,marginBottom:6}}>📢</div>
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:800,fontSize:22,color:'white'}}>Post Free Classified</div>
          <div style={{fontSize:11,color:'rgba(255,255,255,0.8)',marginTop:3}}>{constituency} · Reach thousands of locals</div>
        </div>
      </div>
      {pSubmitted ? (
        <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:32,textAlign:'center'}}>
          <div style={{fontSize:56,marginBottom:12}}>✅</div>
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:800,fontSize:24,color:'#111',marginBottom:8}}>Ad Submitted!</div>
          <div style={{fontSize:14,color:'#555',marginBottom:24}}>Your classified ad will be reviewed and posted shortly.</div>
          <button onClick={()=>{setShowPost(false);setPSubmitted(false);setPTitle('');setPDesc('');setPContact('');setPLocation('');}}
            style={{background:'linear-gradient(135deg,#1e3a8a,#3b82f6)',color:'white',border:'none',borderRadius:12,padding:'14px 32px',fontWeight:800,fontSize:15,cursor:'pointer'}}>Done</button>
        </div>
      ) : (
        <div style={{flex:1,overflowY:'auto',padding:16}}>
          <div style={{background:'white',borderRadius:14,padding:16,marginBottom:12,boxShadow:'0 2px 8px rgba(0,0,0,0.06)'}}>
            <div style={{fontWeight:800,fontSize:14,color:'#111',marginBottom:10}}>Category *</div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6}}>
              {CL_CATS.filter(c=>c!=='All').map(c=>(
                <button key={c} onClick={()=>setPCat(c)} style={{background:pCat===c?'#1e3a8a':'#f8fafc',border:`1.5px solid ${pCat===c?'#1e3a8a':'#e2e8f0'}`,borderRadius:10,padding:'10px 8px',fontSize:12,fontWeight:700,color:pCat===c?'white':'#374151',cursor:'pointer',display:'flex',alignItems:'center',gap:5,justifyContent:'center'}}>
                  {CL_CAT_EMOJI[c]} {c}
                </button>
              ))}
            </div>
          </div>
          <div style={{background:'white',borderRadius:14,padding:16,marginBottom:12,boxShadow:'0 2px 8px rgba(0,0,0,0.06)'}}>
            <div style={{marginBottom:12}}>
              <div style={{fontWeight:700,fontSize:13,color:'#222',marginBottom:6}}>Ad Title <span style={{color:'#e53e3e'}}>*</span></div>
              <input value={pTitle} onChange={e=>setPTitle(e.target.value)} placeholder="e.g. 2BHK Flat for Rent in Kurnool"
                style={{width:'100%',border:'1.5px solid #ddd',borderRadius:10,padding:'12px 14px',fontSize:14,color:'#111',boxSizing:'border-box'}}/>
            </div>
            <div style={{marginBottom:12}}>
              <div style={{fontWeight:700,fontSize:13,color:'#222',marginBottom:6}}>Description <span style={{color:'#e53e3e'}}>*</span></div>
              <textarea value={pDesc} onChange={e=>setPDesc(e.target.value)} placeholder="Describe your ad in detail…"
                style={{width:'100%',border:'1.5px solid #ddd',borderRadius:10,padding:'12px 14px',fontSize:14,color:'#111',height:90,resize:'none',boxSizing:'border-box'}}/>
            </div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10}}>
              <div>
                <div style={{fontWeight:700,fontSize:13,color:'#222',marginBottom:6}}>Location <span style={{color:'#e53e3e'}}>*</span></div>
                <input value={pLocation} onChange={e=>setPLocation(e.target.value)} placeholder={constituency}
                  style={{width:'100%',border:'1.5px solid #ddd',borderRadius:10,padding:'12px',fontSize:13,color:'#111',boxSizing:'border-box'}}/>
              </div>
              <div>
                <div style={{fontWeight:700,fontSize:13,color:'#222',marginBottom:6}}>Phone <span style={{color:'#e53e3e'}}>*</span></div>
                <input value={pContact} onChange={e=>setPContact(e.target.value)} placeholder="98765 43210" type="tel"
                  style={{width:'100%',border:'1.5px solid #ddd',borderRadius:10,padding:'12px',fontSize:13,color:'#111',boxSizing:'border-box'}}/>
              </div>
            </div>
          </div>
          <button onClick={()=>{if(pTitle&&pDesc&&pContact&&pLocation)setPSubmitted(true);}}
            style={{width:'100%',background:'linear-gradient(135deg,#1e3a8a,#3b82f6)',color:'white',border:'none',borderRadius:12,padding:'16px',fontWeight:800,fontSize:16,cursor:'pointer',letterSpacing:0.5}}>
            📢 Submit Free Ad
          </button>
          <div style={{height:24}}/>
        </div>
      )}
    </div>
  );

  // ── INSTAGRAM FULL-SCREEN VIEWER ─────────────────────────────
  if (igIndex !== null) return (
    <InstagramClassifiedsViewer
      items={filtered}
      startIndex={igIndex}
      onClose={() => setIgIndex(null)}
      badgeColor={badgeColor}
    />
  );

  // ── LIST VIEW ──────────────────────────────────────────────────
  return (
    <div style={{width:'100%',height:'100%',background:T.bg,display:'flex',flexDirection:'column',overflow:'hidden'}}>
      <div style={{background:T.bg2,padding:'48px 16px 0',flexShrink:0}}>
        <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:12}}>
          <button onClick={onBack} style={{background:T.bg3,border:'none',borderRadius:8,width:32,height:32,color:T.text,fontSize:16,cursor:'pointer',flexShrink:0}}>←</button>
          <div style={{flex:1}}>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:800,fontSize:20,color:T.text}}>📢 Local Classifieds</div>
            <div style={{fontSize:10,color:T.textMuted}}>{constituency} · {filtered.length} ads</div>
          </div>
          <button onClick={()=>setShowPost(true)} style={{background:T.red,border:'none',borderRadius:10,padding:'8px 12px',color:'white',fontSize:11,fontWeight:700,cursor:'pointer',flexShrink:0}}>+ Post Ad</button>
        </div>
        <div style={{position:'relative',marginBottom:12}}>
          <span style={{position:'absolute',left:12,top:'50%',transform:'translateY(-50%)',fontSize:14,color:T.textMuted}}>🔍</span>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search property, jobs, vehicles…"
            style={{width:'100%',background:T.bg3,border:`1px solid ${T.border}`,borderRadius:10,padding:'10px 14px 10px 34px',color:T.text,fontSize:13,boxSizing:'border-box'}}/>
        </div>
        <div style={{display:'flex',gap:6,overflowX:'auto',paddingBottom:12}}>
          {CL_CATS.map(c=>(
            <button key={c} onClick={()=>setCat(c)} style={{
              display:'flex',alignItems:'center',gap:4,flexShrink:0,
              background:cat===c?T.red:T.bg3,
              border:`1px solid ${cat===c?T.red:T.border}`,
              borderRadius:14,padding:'5px 10px',cursor:'pointer',
            }}>
              <span style={{fontSize:10}}>{CL_CAT_EMOJI[c]}</span>
              <span style={{fontSize:10,fontWeight:600,color:cat===c?'white':T.textMuted,fontFamily:"'Barlow Condensed',sans-serif"}}>{c}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Tap any card to open Instagram viewer */}
      <div style={{flex:1,overflowY:'auto',padding:'10px 14px'}}>
        {filtered.length===0 && (
          <div style={{textAlign:'center',padding:'48px 24px'}}>
            <div style={{fontSize:40,marginBottom:12}}>🔍</div>
            <div style={{fontSize:14,fontWeight:600,color:T.text}}>No ads found</div>
            <div style={{fontSize:12,marginTop:4,color:T.textMuted}}>Try a different category or search</div>
          </div>
        )}
        {filtered.map((cl,idx)=>(
          <div key={cl.id} onClick={()=>setIgIndex(idx)}
            style={{background:T.bg2,borderRadius:14,padding:'12px 14px',marginBottom:10,
              border:`1px solid ${T.border}`,cursor:'pointer',display:'flex',gap:12,
              alignItems:'flex-start',boxShadow:T.isDark?'none':`0 2px 8px ${T.shadow}`}}>
            <div style={{width:50,height:50,borderRadius:12,background:T.bg3,display:'flex',alignItems:'center',justifyContent:'center',fontSize:24,flexShrink:0}}>{cl.emoji}</div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',gap:6,marginBottom:4}}>
                <div style={{fontSize:13,fontWeight:700,color:T.text,lineHeight:1.3,flex:1}}>{cl.title}</div>
                <div style={{background:badgeColor(cl.badge),color:'white',fontSize:8,fontWeight:800,padding:'2px 7px',borderRadius:4,flexShrink:0}}>{cl.badge}</div>
              </div>
              <div style={{fontSize:11,color:T.textMuted,lineHeight:1.4,marginBottom:6}}>{cl.desc.slice(0,70)}…</div>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between'}}>
                <div style={{display:'flex',gap:8}}>
                  <span style={{fontSize:9,color:T.teal}}>📍 {cl.location}</span>
                  <span style={{fontSize:9,color:T.textMuted}}>🕐 {cl.time}</span>
                </div>
                <div style={{display:'flex',alignItems:'center',gap:6,fontSize:9,color:T.textMuted}}>
                  <span>Tap to view ›</span>
                </div>
              </div>
            </div>
          </div>
        ))}
        <div style={{height:20}}/>
      </div>
    </div>
  );
}

