// ════════════════════════════════════════════════════════════════
// UNIFIED VERTICAL FEED VIEWER
// Sakshi/YouTube-Shorts style swipe feed for all 4 categories:
//   1. Shorts  2. Classifieds  3. Bulletins  4. District News
// ════════════════════════════════════════════════════════════════

// ── Data adapter — normalises all 4 sources into FeedItem format ──
function buildFeedItems(type, items, constituency) {
  const today = new Date();
  switch(type) {
    case 'shorts':
      return items.map((s, i) => ({
        id:       `s${i}`,
        type:     'shorts',
        headline: s.titleTe,
        headlineEn: s.titleEn,
        ytId:     s.ytId,
        thumb:    s.img,
        reporter: s.channel,
        location: constituency || 'కర్నూలు',
        time:     s.duration,
        date:     'నేడు',
        category: 'Shorts',
        views:    s.views,
        live:     s.live,
        fullText: s.titleTe + '\n\n' + s.titleEn,
        uploadedAt: new Date(today - i * 3600000),
      }));
    case 'classifieds':
      return items.map((c, i) => ({
        id:       `c${c.id}`,
        type:     'classifieds',
        headline: c.title,
        headlineEn: c.title,
        ytId:     null,
        thumb:    CL_CAT_IMG[c.cat] || CL_CAT_IMG['Events'],
        reporter: c.contact,
        location: c.location,
        time:     c.time,
        date:     c.time,
        category: c.cat,
        views:    '',
        live:     false,
        fullText: c.desc,
        badge:    c.badge,
        contact:  c.contact,
        uploadedAt: new Date(today - i * 7200000),
      }));
    case 'bulletins':
      return items.map((b, i) => ({
        id:       `b${i}`,
        type:     'bulletins',
        headline: b.titleTe,
        headlineEn: '',
        ytId:     b.ytId,
        thumb:    `https://img.youtube.com/vi/${b.ytId}/maxresdefault.jpg`,
        reporter: b.channel,
        location: constituency || 'కర్నూలు',
        time:     b.broadcastTime,
        date:     'నేడు',
        category: 'ప్రసారాలు',
        views:    '',
        live:     false,
        fullText: `${b.titleTe} — ${b.broadcastTime} ప్రసారం`,
        uploadedAt: new Date(today - i * 3600000),
      }));
    case 'news':
      return items.map((n, i) => ({
        id:       `n${n.id}`,
        type:     'news',
        headline: n.title || n.titleTe,
        headlineEn: n.titleEn || '',
        ytId:     null,
        thumb:    (() => {
          const catImgs = {
            District:'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=600&q=80',
            State:'https://images.unsplash.com/photo-1529107386315-e1a2ed48a620?w=600&q=80',
            National:'https://images.unsplash.com/photo-1524492412937-b28074a5d7da?w=600&q=80',
            World:'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=600&q=80',
            Sports:'https://images.unsplash.com/photo-1461896836934-ffe607ba8211?w=600&q=80',
            Health:'https://images.unsplash.com/photo-1579684385127-1ef15d508118?w=600&q=80',
            Business:'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=600&q=80',
            Agri:'https://images.unsplash.com/photo-1574943320219-553eb213f72d?w=600&q=80',
            Crime:'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=600&q=80',
          };
          return n.thumbnail || catImgs[n.cat] || catImgs.District;
        })(),
        reporter: n.reporter || n.channel || 'LocalAI TV',
        location: n.location || n.district || constituency || 'కర్నూలు',
        time:     n.time,
        date:     'నేడు',
        category: n.cat,
        views:    n.views,
        live:     n.live,
        fullText: n.title + (n.titleEn ? '\n\n' + n.titleEn : ''),
        uploadedAt: new Date(today - i * 1800000),
      }));
    default:
      return [];
  }
}

// ── Comment Drawer ──────────────────────────────────────────────
function CommentDrawer({ open, onClose, itemId }) {
  const { T } = useAppTheme();
  const [text, setText] = useState('');
  const MOCK_COMMENTS = [
    { user:'రాజు కె', time:'2m ago', text:'చాలా మంచి వార్త! 👏', likes:12 },
    { user:'Priya D', time:'5m ago', text:'కర్నూలు అభివృద్ధి జోరుగా సాగుతోంది', likes:8 },
    { user:'Suresh R', time:'12m ago', text:'LocalAI TV best news channel! 🎉', likes:24 },
    { user:'అనిత',    time:'18m ago', text:'Very useful information. Thank you!', likes:5 },
    { user:'వెంకట్',  time:'25m ago', text:'ఎప్పటికీ ఇలాంటి వార్తలు చాలా అవసరం', likes:17 },
  ];
  if (!open) return null;
  return (
    <div onClick={onClose}
      style={{ position:'absolute', inset:0, zIndex:40,
        background:'rgba(0,0,0,0.55)', display:'flex',
        flexDirection:'column', justifyContent:'flex-end' }}>
      <div onClick={e=>e.stopPropagation()}
        style={{ background:T.isDark?'#111':'#fff', borderRadius:'20px 20px 0 0',
          maxHeight:'65%', display:'flex', flexDirection:'column',
          boxShadow:'0 -8px 40px rgba(0,0,0,0.35)' }}>
        {/* Header */}
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between',
          padding:'14px 18px 12px', borderBottom:`1px solid ${T.border}` }}>
          <span style={{ fontFamily:"'Barlow Condensed',sans-serif", fontWeight:800,
            fontSize:16, color:T.text }}>💬 Comments ({MOCK_COMMENTS.length})</span>
          <button onClick={onClose} style={{ background:'none', border:'none',
            fontSize:20, color:T.textMuted, cursor:'pointer' }}>✕</button>
        </div>
        {/* Comment list */}
        <div style={{ flex:1, overflowY:'auto', padding:'12px 18px',
          display:'flex', flexDirection:'column', gap:14 }}>
          {MOCK_COMMENTS.map((c,i) => (
            <div key={i} style={{ display:'flex', gap:10 }}>
              <div style={{ width:34, height:34, borderRadius:'50%', flexShrink:0,
                background:`linear-gradient(135deg,${T.red},#FF6B00)`,
                display:'flex', alignItems:'center', justifyContent:'center',
                fontSize:13, fontWeight:700, color:'white' }}>
                {c.user[0]}
              </div>
              <div style={{ flex:1 }}>
                <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:3 }}>
                  <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                    fontWeight:700, fontSize:13, color:T.text }}>{c.user}</span>
                  <span style={{ fontSize:10, color:T.textMuted }}>{c.time}</span>
                </div>
                <div style={{ fontSize:13, color:T.text, lineHeight:1.5,
                  fontFamily:"'Noto Sans Telugu',sans-serif" }}>{c.text}</div>
                <div style={{ fontSize:10, color:T.textMuted, marginTop:4 }}>❤️ {c.likes}</div>
              </div>
            </div>
          ))}
        </div>
        {/* Input */}
        <div style={{ display:'flex', gap:8, padding:'10px 16px 20px',
          borderTop:`1px solid ${T.border}` }}>
          <input value={text} onChange={e=>setText(e.target.value)}
            placeholder="మీ అభిప్రాయం రాయండి..."
            style={{ flex:1, background:T.bg3, border:`1px solid ${T.border}`,
              borderRadius:22, padding:'10px 16px', fontSize:13,
              fontFamily:"'Noto Sans Telugu',sans-serif", color:T.text,
              outline:'none' }}/>
          <button onClick={()=>setText('')}
            style={{ width:42, height:42, borderRadius:'50%',
              background:text ? T.red : T.bg3,
              border:'none', cursor:'pointer',
              display:'flex', alignItems:'center', justifyContent:'center',
              fontSize:17, transition:'background 0.2s',
              color: text ? 'white' : T.textMuted }}>⬆</button>
        </div>
      </div>
    </div>
  );
}

// ── Rating Drawer ───────────────────────────────────────────────
function RatingDrawer({ open, onClose }) {
  const { T } = useAppTheme();
  const [rating, setRating] = useState(0);
  const [submitted, setSubmitted] = useState(false);
  if (!open) return null;
  return (
    <div onClick={onClose}
      style={{ position:'absolute', inset:0, zIndex:40,
        background:'rgba(0,0,0,0.55)', display:'flex',
        flexDirection:'column', justifyContent:'flex-end' }}>
      <div onClick={e=>e.stopPropagation()}
        style={{ background:T.isDark?'#111':'#fff', borderRadius:'20px 20px 0 0',
          padding:'20px 24px 36px', textAlign:'center',
          boxShadow:'0 -8px 40px rgba(0,0,0,0.35)' }}>
        <div style={{ width:40, height:4, background:T.border,
          borderRadius:2, margin:'0 auto 16px' }}/>
        {submitted ? (
          <>
            <div style={{ fontSize:48, marginBottom:12 }}>🙏</div>
            <div style={{ fontFamily:"'Noto Sans Telugu',sans-serif",
              fontSize:16, fontWeight:700, color:T.text, marginBottom:6 }}>
              ధన్యవాదాలు!
            </div>
            <div style={{ fontSize:13, color:T.textMuted }}>
              మీ రేటింగ్ నమోదు అయింది
            </div>
          </>
        ) : (
          <>
            <div style={{ fontFamily:"'Noto Sans Telugu',sans-serif",
              fontSize:17, fontWeight:700, color:T.text, marginBottom:4 }}>
              ఈ వార్తను రేట్ చేయండి
            </div>
            <div style={{ fontSize:12, color:T.textMuted, marginBottom:20 }}>
              Rate this news
            </div>
            <div style={{ display:'flex', justifyContent:'center', gap:12, marginBottom:24 }}>
              {[1,2,3,4,5].map(star => (
                <button key={star} onClick={()=>setRating(star)}
                  style={{ fontSize:36, background:'none', border:'none',
                    cursor:'pointer', transition:'transform 0.15s',
                    transform: star <= rating ? 'scale(1.2)' : 'scale(1)',
                    filter: star <= rating ? 'none' : 'grayscale(1) opacity(0.4)' }}>
                  ⭐
                </button>
              ))}
            </div>
            <button onClick={()=>{ if(rating) { setSubmitted(true); setTimeout(onClose,1500); }}}
              disabled={!rating}
              style={{ width:'100%', padding:'14px',
                background: rating ? T.red : T.bg3,
                color: rating ? 'white' : T.textMuted,
                border:'none', borderRadius:14, fontSize:15,
                fontFamily:"'Barlow Condensed',sans-serif",
                fontWeight:800, letterSpacing:0.5, cursor: rating ? 'pointer' : 'default',
                transition:'all 0.2s' }}>
              Submit Rating
            </button>
          </>
        )}
      </div>
    </div>
  );
}

// ── Single Feed Item ────────────────────────────────────────────
function FeedItem({ item, isActive, onShare }) {
  const { T } = useAppTheme();
  const [liked,     setLiked]     = useState(false);
  const [disliked,  setDisliked]  = useState(false);
  const [showComment, setShowComment] = useState(false);
  const [showRating,  setShowRating]  = useState(false);
  const [showHeart,   setShowHeart]   = useState(false);
  const [likeCount,   setLikeCount]   = useState(Math.floor(Math.random()*200)+10);
  const lastTap = useRef(0);

  const handleLike = () => {
    if (!liked) setLikeCount(c=>c+1);
    else setLikeCount(c=>c-1);
    setLiked(l=>!l);
    setDisliked(false);
  };
  const handleDislike = () => {
    if (liked) setLikeCount(c=>c-1);
    setDisliked(d=>!d);
    setLiked(false);
  };
  const handleDoubleTap = () => {
    const now = Date.now();
    if (now - lastTap.current < 300) {
      setLiked(true);
      setLikeCount(c=>c+1);
      setShowHeart(true);
      setTimeout(()=>setShowHeart(false), 700);
    }
    lastTap.current = now;
  };

  return (
    <div style={{ width:'100%', height:'100%', display:'flex',
      flexDirection:'column', position:'relative', background:'#000' }}>

      {/* ── Double-tap heart animation ── */}
      {showHeart && (
        <div style={{ position:'absolute', top:'25%', left:'50%',
          transform:'translate(-50%,-50%)', zIndex:30,
          fontSize:90, animation:'heartPop 0.65s ease forwards',
          pointerEvents:'none' }}>❤️</div>
      )}

      {/* ── VIDEO / THUMBNAIL (35-40% of screen) ── */}
      <div onTouchStart={handleDoubleTap}
        style={{ height:'38%', position:'relative',
          background:'#000', flexShrink:0, overflow:'hidden' }}>
        {item.ytId && isActive ? (
          <iframe
            src={`https://www.youtube.com/embed/${item.ytId}?autoplay=1&mute=0&loop=1&playlist=${item.ytId}&controls=1&rel=0&modestbranding=1&cc_load_policy=0`}
            title={item.headline}
            allow="autoplay; encrypted-media; fullscreen"
            allowFullScreen
            style={{ width:'100%', height:'100%', border:'none', display:'block' }}
          />
        ) : (
          <div style={{ width:'100%', height:'100%', position:'relative' }}>
            <img src={item.thumb}
              alt={item.headline}
              style={{ width:'100%', height:'100%', objectFit:'cover' }}
              onError={e => { e.target.src='https://images.unsplash.com/photo-1504711434969-e33886168f5c?w=600&q=80'; }}
            />
            {/* Play overlay if has video */}
            {item.ytId && !isActive && (
              <div style={{ position:'absolute', inset:0,
                display:'flex', alignItems:'center', justifyContent:'center',
                background:'rgba(0,0,0,0.25)' }}>
                <div style={{ width:54, height:54, borderRadius:'50%',
                  background:'rgba(255,255,255,0.92)',
                  display:'flex', alignItems:'center', justifyContent:'center' }}>
                  <div style={{ width:0, height:0, marginLeft:5,
                    borderTop:'14px solid transparent',
                    borderBottom:'14px solid transparent',
                    borderLeft:'22px solid #D0021B' }}/>
                </div>
              </div>
            )}
            {/* LIVE badge */}
            {item.live && (
              <div style={{ position:'absolute', top:10, left:10,
                display:'flex', alignItems:'center', gap:4,
                background:'#D0021B', borderRadius:6, padding:'4px 10px',
                boxShadow:'0 2px 8px rgba(208,2,27,0.4)' }}>
                <div style={{ width:6, height:6, borderRadius:'50%',
                  background:'white', animation:'blink 1s infinite' }}/>
                <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                  fontWeight:900, fontSize:11, color:'white', letterSpacing:1.2 }}>LIVE</span>
              </div>
            )}
            {/* Duration */}
            {item.time && !item.live && item.type==='shorts' && (
              <div style={{ position:'absolute', bottom:8, right:10,
                background:'rgba(0,0,0,0.75)', borderRadius:5, padding:'3px 8px' }}>
                <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                  fontSize:11, fontWeight:700, color:'white' }}>▶ {item.time}</span>
              </div>
            )}
            {/* Category badge */}
            {item.type !== 'shorts' && (
              <div style={{ position:'absolute', top:10, right:10,
                background:'rgba(0,0,0,0.7)', borderRadius:6, padding:'4px 10px',
                border:`1px solid ${T.red}44` }}>
                <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                  fontSize:10, fontWeight:700, color:'white', letterSpacing:0.5 }}>
                  {item.category}
                </span>
              </div>
            )}
          </div>
        )}
        {/* Bottom fade into content */}
        <div style={{ position:'absolute', bottom:0, left:0, right:0, height:30,
          background:'linear-gradient(0deg,#000 0%,transparent 100%)',
          pointerEvents:'none' }}/>
      </div>

      {/* ── SCROLLABLE CONTENT AREA (60-65%) ── */}
      <div style={{ flex:1, overflowY:'auto', scrollbarWidth:'none',
        WebkitOverflowScrolling:'touch',
        background:'#000',
        display:'flex', flexDirection:'column' }}>

        {/* Headline */}
        <div style={{ padding:'14px 18px 8px' }}>
          <h2 style={{ margin:0,
            fontFamily:"'Noto Sans Telugu',sans-serif",
            fontWeight:800, fontSize:18, lineHeight:1.5,
            color:'white', marginBottom: item.headlineEn ? 6 : 0 }}>
            {item.headline}
          </h2>
          {item.headlineEn && item.headlineEn !== item.headline && (
            <p style={{ margin:0, fontFamily:"'Barlow',sans-serif",
              fontSize:13, color:'rgba(255,255,255,0.55)', lineHeight:1.5 }}>
              {item.headlineEn}
            </p>
          )}
        </div>

        {/* ── SharedActionBar — below video, above text ── */}
        <SharedActionBar
          itemId={`feed_${item.id}_${item.type}`}
          onShare={onShare}
          onComment={()=>setShowComment(true)}
          compact={false}
        />

        {/* ── FULL TEXT ── */}        {/* ── FULL TEXT ── */}
        <div style={{ padding:'14px 18px 10px' }}>
          {item.type === 'classifieds' && item.badge && (
            <div style={{ display:'inline-flex', alignItems:'center',
              background:'rgba(208,2,27,0.15)', border:'1px solid rgba(208,2,27,0.3)',
              borderRadius:8, padding:'4px 12px', marginBottom:10 }}>
              <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                fontWeight:800, fontSize:13, color:T.red, letterSpacing:0.5 }}>
                {item.badge}
              </span>
            </div>
          )}
          <p style={{ margin:0, fontFamily:"'Noto Sans Telugu',sans-serif",
            fontSize:14, lineHeight:1.8, color:'rgba(255,255,255,0.82)',
            whiteSpace:'pre-line' }}>
            {item.fullText}
          </p>
          {/* Classifieds: call+WhatsApp */}
          {item.type === 'classifieds' && item.contact && (
            <div style={{ display:'flex', gap:10, marginTop:16 }}>
              <button onClick={()=>window.open(`tel:+91${item.contact.replace(/\s/g,'')}`, '_blank')}
                style={{ flex:1, background:'linear-gradient(135deg,#059669,#047857)',
                  border:'none', borderRadius:12, padding:'13px',
                  fontFamily:"'Barlow Condensed',sans-serif",
                  fontWeight:800, fontSize:14, color:'white', cursor:'pointer',
                  display:'flex', alignItems:'center', justifyContent:'center', gap:6 }}>
                📞 Call Now
              </button>
              <button onClick={()=>window.open(`https://wa.me/91${item.contact.replace(/\s/g,'')}?text=${encodeURIComponent('Hi, I saw your ad on LocalAI TV: '+item.headline)}`, '_blank')}
                style={{ flex:1, background:'linear-gradient(135deg,#25D366,#128C7E)',
                  border:'none', borderRadius:12, padding:'13px',
                  fontFamily:"'Barlow Condensed',sans-serif",
                  fontWeight:800, fontSize:14, color:'white', cursor:'pointer',
                  display:'flex', alignItems:'center', justifyContent:'center', gap:6 }}>
                💬 WhatsApp
              </button>
            </div>
          )}
        </div>

        {/* ── REPORTER / METADATA ── */}
        <div style={{ margin:'4px 18px 16px',
          background:'rgba(255,255,255,0.05)',
          borderRadius:12, padding:'12px 14px',
          border:'1px solid rgba(255,255,255,0.08)' }}>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr',
            gap:8 }}>
            {[
              { icon:'👤', label:'Reporter', value: item.reporter },
              { icon:'📍', label:'Location', value: item.location },
              { icon:'📂', label:'Category', value: item.category },
              { icon:'🕐', label:'Time',     value: item.time },
            ].map(({icon,label,value}) => value ? (
              <div key={label}>
                <div style={{ fontSize:9, color:'rgba(255,255,255,0.35)',
                  fontFamily:"'Barlow Condensed',sans-serif",
                  letterSpacing:0.8, marginBottom:2, textTransform:'uppercase' }}>
                  {icon} {label}
                </div>
                <div style={{ fontFamily:"'Barlow Condensed',sans-serif",
                  fontSize:12, fontWeight:600,
                  color:'rgba(255,255,255,0.7)', lineHeight:1.3 }}>
                  {value}
                </div>
              </div>
            ) : null)}
          </div>
        </div>

        {/* Swipe hint */}
        <div style={{ textAlign:'center', padding:'4px 0 20px' }}>
          <span style={{ fontSize:11, color:'rgba(255,255,255,0.18)',
            fontFamily:"'Barlow',sans-serif", letterSpacing:0.3 }}>
            ↑ swipe up for next
          </span>
        </div>
      </div>

      {/* Drawers */}
      <CommentDrawer open={showComment} onClose={()=>setShowComment(false)} itemId={item.id}/>
      <RatingDrawer  open={showRating}  onClose={()=>setShowRating(false)}/>
    </div>
  );
}

// ── MAIN UnifiedFeedViewer ──────────────────────────────────────
/* ═══════════════════════════════════════════════════════════════════════
   TERMINAL CONTINUATION CARD — Phase 6.5: emotional continuation hook
   ───────────────────────────────────────────────────────────────────────
   Renders at the end of the Shorts feed when the user swipes past the
   last real item. Mohan's brief: "the network continues beyond this
   rail" — NOT an aggressive CTA, NOT a growth-hack. Pure emotional
   continuation. No buttons. The user can swipe back to revisit or
   close via the existing top-right close button.

   Reuses Phase-3 primitives — ott-halo (ambient red glow), ott-ai-pulse
   (red dot identity) — so the terminal moment feels continuous with the
   live-broadcast hero language established at the homepage top.
   ═══════════════════════════════════════════════════════════════════════ */
function TerminalContinuationCard({ type, title }) {
  // Type-aware Telugu — keeps the moment authentic to the content type
  const teByType = {
    shorts:      'మరిన్ని Shorts త్వరలో',
    bulletins:   'మరిన్ని ప్రసారాలు త్వరలో',
    classifieds: 'మరిన్ని listings త్వరలో',
    news:        'మరిన్ని వార్తలు త్వరలో',
  };
  const teLine = teByType[type] || teByType.news;

  return (
    <div style={{
      width:'100%', height:'100%', position:'relative',
      background:'#000', overflow:'hidden',
      display:'flex', alignItems:'center', justifyContent:'center',
      padding:'40px 28px',
    }}>
      {/* Ambient halo — reuses the Phase-3 broadcast hero language.
          Two desync layers (4.2s + 5.7s) to match the live-player feel. */}
      <div className="ott-halo" style={{
        position:'absolute', inset:'18% 12%',
        borderRadius:'50%',
        background:'radial-gradient(ellipse at center, rgba(225,29,72,0.22) 0%, rgba(225,29,72,0.08) 50%, transparent 75%)',
        filter:'blur(34px)',
        pointerEvents:'none',
      }}/>
      <div className="ott-halo2" style={{
        position:'absolute', inset:'24% 18%',
        borderRadius:'50%',
        background:'radial-gradient(ellipse at center, rgba(225,29,72,0.14) 0%, rgba(225,29,72,0.05) 55%, transparent 80%)',
        filter:'blur(42px)',
        pointerEvents:'none',
      }}/>

      {/* Centered content stack */}
      <div style={{
        position:'relative', zIndex:1,
        display:'flex', flexDirection:'column', alignItems:'center',
        gap:14, maxWidth:340, textAlign:'center',
      }}>
        {/* Eyebrow — identity continuity with live AI ribbon */}
        <div style={{display:'flex', alignItems:'center', gap:8}}>
          <div className="ott-ai-pulse" style={{
            width:7, height:7, borderRadius:'50%',
            background:OTT.color.red,
          }}/>
          <span style={{
            fontFamily:OTT.type.mono.font, fontSize:10.5, fontWeight:900,
            color:'#fff', letterSpacing:2.2, textTransform:'uppercase',
          }}>The&nbsp;Network&nbsp;Continues</span>
        </div>

        {/* Big Telugu — the emotional anchor */}
        <div style={{
          fontFamily:OTT.type.te.font, fontSize:26, fontWeight:800,
          color:'#fff', lineHeight:1.32, letterSpacing:0.3,
          textShadow:'0 2px 18px rgba(225,29,72,0.32)',
          marginTop:6,
        }}>{teLine}</div>

        {/* English subtitle — softer, sets the mood */}
        <div style={{
          fontFamily:OTT.type.body.font, fontSize:13, fontWeight:500,
          color:'rgba(255,255,255,0.62)', lineHeight:1.5,
          letterSpacing:0.15, maxWidth:300,
        }}>
          The network continues beyond this rail.
          {title ? <><br/>More from <span style={{color:'rgba(255,255,255,0.82)', fontWeight:700}}>{title}</span> is on the way.</> : null}
        </div>

        {/* Hairline separator + wordmark — restrained closure */}
        <div style={{
          marginTop:22, paddingTop:18,
          borderTop:'1px solid rgba(255,255,255,0.10)',
          display:'flex', alignItems:'center', gap:8,
        }}>
          <span style={{
            fontFamily:OTT.type.mono.font, fontSize:9, fontWeight:800,
            color:'rgba(255,255,255,0.42)', letterSpacing:2.0, textTransform:'uppercase',
          }}>LocalAI&nbsp;TV</span>
          <span style={{
            width:3, height:3, borderRadius:'50%',
            background:'rgba(255,255,255,0.22)',
          }}/>
          <span style={{
            fontFamily:OTT.type.mono.font, fontSize:9, fontWeight:700,
            color:'rgba(255,184,0,0.65)', letterSpacing:1.6, textTransform:'uppercase',
          }}>AI&nbsp;Curated</span>
        </div>

        {/* Subtle swipe-down hint — appears, doesn't shout */}
        <div style={{
          marginTop:8,
          fontFamily:OTT.type.body.font, fontSize:10.5, fontWeight:500,
          color:'rgba(255,255,255,0.32)', letterSpacing:0.4,
        }}>
          ↓&nbsp;&nbsp;swipe down to revisit
        </div>
      </div>
    </div>
  );
}

function UnifiedFeedViewer({ type, items, startIdx, onClose, title, activeChannel }) {
  const { T } = useAppTheme();
  const feedItems   = useMemo(()=>buildFeedItems(type, items, activeChannel?.nameEn), [type, items]);
  const [idx, setIdx]           = useState(startIdx || 0);
  const [showShareSheet, setShowShareSheet] = useState(false);
  const total   = feedItems.length;
  const cur     = feedItems[idx] || feedItems[0];

  // Phase 6.5 — terminal continuation card. Shorts only (the addictive
  // surface). For other types, the existing edge-bounce behavior is
  // more appropriate (bulletins/classifieds/news are finite content
  // the user explicitly opened).
  const hasTerminal  = type === 'shorts';
  const TERMINAL_IDX = feedItems.length;             // virtual index for the terminal
  const lastNavIdx   = hasTerminal ? TERMINAL_IDX : feedItems.length - 1;
  const onTerminal   = hasTerminal && idx === TERMINAL_IDX;
  const isShareable  = !onTerminal && cur;           // disable share on terminal

  /* ═══════════════════════════════════════════════════════════════════
     PHASE-6 ELITE SHORTS POLISH — drag-with-peek + velocity-aware snap
     ───────────────────────────────────────────────────────────────────
     Replaces the old touchend-only swipe with real-time drag tracking:
     - As the user drags, the feed translates with their finger
     - Adjacent items (prev/next) peek into view at the edges
     - On release: snap based on (a) distance > 25% viewport OR (b)
       velocity > 0.55 px/ms — fast flick wins over short distance
     - Edge resistance: at idx 0 dragging down (or idx last up), drag
       is dampened to 35% — communicates "you're at the edge"
     - Snap duration scales with velocity (fast flick = snappier feel)
     - Adjacent FeedItems mount but isActive=false → they show
       thumbnails only, no video iframe (perf-safe, no audio bleed)
     ═══════════════════════════════════════════════════════════════════ */
  const [dragOffset, setDragOffset] = useState(0); // px; positive = finger moved down
  const [isSnapping, setIsSnapping] = useState(false); // controls transition vs raw transform
  const [snapDur,    setSnapDur]    = useState(220);   // ms; adapts to flick velocity
  const containerRef = useRef(null);
  const [containerH, setContainerH] = useState(0);

  const touchStartY = useRef(0);
  const touchStartX = useRef(0);
  const touchStartT = useRef(0);
  const touchLastY  = useRef(0);
  const touchLastT  = useRef(0);
  const moved       = useRef(false);
  const horizGuess  = useRef(false); // locks once we determine drag is horizontal

  // Lock body scroll
  useEffect(()=>{ document.body.style.overflow='hidden'; return ()=>{ document.body.style.overflow=''; }; },[]);

  // Measure container height for the drag-with-peek layout
  useEffect(() => {
    const update = () => {
      if (containerRef.current) setContainerH(containerRef.current.clientHeight);
    };
    update();
    window.addEventListener('resize', update);
    return () => window.removeEventListener('resize', update);
  }, []);

  // Snappy spring curve — overshoots slightly on settle for premium feel.
  // Used for both forward navigation and spring-back.
  const SNAP_CURVE = 'cubic-bezier(0.34,1.56,0.64,1)';

  const goNext = (velocity = 0) => {
    if (idx >= lastNavIdx) {
      // Edge: spring back to 0
      setIsSnapping(true);
      setSnapDur(260);
      setDragOffset(0);
      setTimeout(()=>setIsSnapping(false), 260);
      return;
    }
    const dur = velocity > 1.2 ? 180 : velocity > 0.6 ? 220 : 280;
    setSnapDur(dur);
    setIsSnapping(true);
    setDragOffset(-containerH); // animate current item off the top
    setTimeout(() => {
      setIsSnapping(false);
      setDragOffset(0);
      setIdx(i => i + 1);
    }, dur);
  };
  const goPrev = (velocity = 0) => {
    if (idx <= 0) {
      setIsSnapping(true);
      setSnapDur(260);
      setDragOffset(0);
      setTimeout(()=>setIsSnapping(false), 260);
      return;
    }
    const dur = velocity > 1.2 ? 180 : velocity > 0.6 ? 220 : 280;
    setSnapDur(dur);
    setIsSnapping(true);
    setDragOffset(containerH); // animate current item off the bottom
    setTimeout(() => {
      setIsSnapping(false);
      setDragOffset(0);
      setIdx(i => i - 1);
    }, dur);
  };

  const onTouchStart = e => {
    if (isSnapping) return; // ignore touches mid-animation
    touchStartY.current = e.touches[0].clientY;
    touchStartX.current = e.touches[0].clientX;
    touchStartT.current = performance.now();
    touchLastY.current  = touchStartY.current;
    touchLastT.current  = touchStartT.current;
    moved.current       = false;
    horizGuess.current  = false;
    setIsSnapping(false);
  };

  const onTouchMove = e => {
    if (isSnapping) return;
    const y  = e.touches[0].clientY;
    const x  = e.touches[0].clientX;
    const dy = y - touchStartY.current;
    const dx = x - touchStartX.current;

    // Determine drag axis once movement exceeds a small threshold
    if (!moved.current && Math.hypot(dx, dy) > 8) {
      moved.current = true;
      horizGuess.current = Math.abs(dx) > Math.abs(dy) * 1.4;
    }
    if (horizGuess.current) return; // let horizontal scroll happen elsewhere

    // Edge resistance: clamp at idx=0 (drag down) and idx=lastNavIdx (drag up).
    // lastNavIdx accounts for the terminal continuation card on shorts.
    let offset = dy;
    if (idx === 0 && dy > 0)              offset = dy * 0.35;
    else if (idx === lastNavIdx && dy < 0) offset = dy * 0.35;

    setDragOffset(offset);
    touchLastY.current = y;
    touchLastT.current = performance.now();
  };

  const onTouchEnd = e => {
    if (isSnapping || !moved.current || horizGuess.current) {
      // Treat as a tap or non-vertical gesture — spring back to 0
      if (dragOffset !== 0) {
        setIsSnapping(true);
        setSnapDur(220);
        setDragOffset(0);
        setTimeout(()=>setIsSnapping(false), 220);
      }
      return;
    }

    const dy = touchLastY.current - touchStartY.current; // total drag
    const dt = Math.max(1, touchLastT.current - touchStartT.current);
    const velocity = Math.abs(dy) / dt; // px/ms, magnitude

    const DIST_THRESH = Math.max(60, containerH * 0.22); // 22% of viewport
    const VEL_THRESH  = 0.55; // ~550 px/sec

    const wantNext = (dy < -DIST_THRESH || (dy < -20 && velocity > VEL_THRESH));
    const wantPrev = (dy >  DIST_THRESH || (dy >  20 && velocity > VEL_THRESH));

    if (wantNext)      goNext(velocity);
    else if (wantPrev) goPrev(velocity);
    else {
      // Spring back to 0
      setIsSnapping(true);
      setSnapDur(220);
      setDragOffset(0);
      setTimeout(()=>setIsSnapping(false), 220);
    }
  };

  // Keyboard nav
  useEffect(()=>{
    const h = e => {
      if (e.key==='ArrowUp')    goNext();
      if (e.key==='ArrowDown')  goPrev();
      if (e.key==='Escape')     onClose();
    };
    window.addEventListener('keydown', h);
    return ()=>window.removeEventListener('keydown', h);
  },[idx, containerH]);

  const shareText = cur ? encodeURIComponent(`${cur.headline}\n📱 LocalAI TV: https://localaitv.com/app`) : '';
  const enc = encodeURIComponent;

  const SHARE_PLATFORMS = [
    { label:'WhatsApp',  color:'#25D366', bg:'rgba(37,211,102,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="#25D366"><path d="M16 2C8.28 2 2 8.28 2 16c0 2.46.67 4.76 1.83 6.74L2 30l7.44-1.79A13.94 13.94 0 0016 30c7.72 0 14-6.28 14-14S23.72 2 16 2zm7.1 19.1c-.3.84-1.76 1.6-2.4 1.7-.62.1-1.4.14-2.26-.14a20.6 20.6 0 01-2.04-.75c-3.58-1.55-5.92-5.16-6.1-5.4-.18-.24-1.46-1.94-1.46-3.7s.92-2.62 1.26-2.98c.3-.34.66-.42.88-.42l.64.01c.2 0 .48-.08.74.56.28.66.94 2.3.02 2.56-.18.06-.34.14-.5.22-.28.14-.52.3-.36.6.16.3.7 1.16 1.5 1.88l1.44 1.14c.3.16.6.12.82-.12.22-.24.9-1.04 1.14-1.4.24-.36.48-.3.8-.18.32.12 2.02.96 2.36 1.13.34.18.58.26.66.4.08.16.08.9-.22 1.74z"/></svg>,
      action:()=>window.open(`https://api.whatsapp.com/send?text=${shareText}`,'_blank') },
    { label:'Telegram',  color:'#0088CC', bg:'rgba(0,136,204,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="#0088CC"><path d="M16 2C8.27 2 2 8.27 2 16s6.27 14 14 14 14-6.27 14-14S23.73 2 16 2zm6.84 9.58l-2.36 11.12c-.18.8-.64 1-1.3.62l-3.6-2.65-1.73 1.67c-.2.2-.36.36-.73.36l.26-3.68 6.7-6.05c.3-.26-.06-.4-.44-.14l-8.28 5.21-3.57-1.12c-.78-.24-.8-.78.16-1.15l13.93-5.37c.64-.24 1.2.14.96 1.18z"/></svg>,
      action:()=>window.open(`https://t.me/share/url?url=${enc('https://localaitv.com/app')}&text=${shareText}`,'_blank') },
    { label:'Facebook',  color:'#1877F2', bg:'rgba(24,119,242,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="#1877F2"><path d="M16 2C8.27 2 2 8.27 2 16c0 6.99 5.12 12.77 11.81 13.82V19.9h-3.55V16h3.55v-3.08c0-3.51 2.09-5.44 5.28-5.44 1.53 0 3.12.27 3.12.27v3.44h-1.76c-1.73 0-2.27 1.07-2.27 2.17V16h3.87l-.62 3.9h-3.25v9.92C24.88 28.77 30 22.99 30 16c0-7.73-6.27-14-14-14z"/></svg>,
      action:()=>window.open(`https://www.facebook.com/sharer/sharer.php?u=${enc('https://localaitv.com/app')}`,'_blank') },
    { label:'X/Twitter', color:'#fff',    bg:'rgba(255,255,255,0.1)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="white"><path d="M18.24 14.17L27.1 4h-2.1l-7.7 8.95L11 4H4l9.3 13.53L4 28h2.1l8.13-9.45L21 28h7L18.24 14.17z"/></svg>,
      action:()=>window.open(`https://twitter.com/intent/tweet?text=${shareText}`,'_blank') },
    { label:'Email',     color:'#EA4335', bg:'rgba(234,67,53,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="none"><rect x="2" y="6" width="28" height="20" rx="3" stroke="#EA4335" strokeWidth="2.2"/><path d="M2 10l14 9 14-9" stroke="#EA4335" strokeWidth="2.2" strokeLinecap="round"/></svg>,
      action:()=>window.open(`mailto:?subject=${enc(cur?.headline||'')}&body=${shareText}`,'_blank') },
    { label:'More',      color:'#9CA3AF', bg:'rgba(156,163,175,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 24 24" fill="none" stroke="#9CA3AF" strokeWidth={2.2} strokeLinecap="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>,
      action:()=>navigator.share?navigator.share({title:cur?.headline,text:decodeURIComponent(shareText),url:'https://localaitv.com/app'}).catch(()=>{}):null },
  ];

  if (!cur) return null;

  return (
    <div style={{ position:'fixed', inset:0, zIndex:300,
      background:'#000', display:'flex', flexDirection:'column',
      overflow:'hidden' }}>

      {/* ── TOP CHROME ── */}
      <div style={{ position:'absolute', top:0, left:0, right:0, zIndex:20,
        paddingTop:52 }}>
        {/* Progress bars — on terminal, all bars read as completed */}
        <div style={{ display:'flex', gap:2, padding:'0 12px 10px' }}>
          {feedItems.map((_,i)=>(
            <div key={i} style={{ flex:1, height:2.5, borderRadius:2,
              background: onTerminal
                ? 'rgba(255,255,255,0.9)'
                : i<idx?'rgba(255,255,255,0.9)':i===idx?'rgba(255,255,255,0.85)':'rgba(255,255,255,0.2)',
              transition:'background 0.3s' }}/>
          ))}
        </div>
        {/* Title bar */}
        <div style={{ display:'flex', alignItems:'center',
          padding:'0 14px 10px',
          background:'linear-gradient(180deg,rgba(0,0,0,0.75) 0%,transparent 100%)' }}>
          <button onClick={onClose} style={{ width:38,height:38,borderRadius:'50%',
            background:'rgba(0,0,0,0.55)',border:'1.5px solid rgba(255,255,255,0.22)',
            color:'white',fontSize:18,cursor:'pointer',flexShrink:0,
            display:'flex',alignItems:'center',justifyContent:'center' }}>←</button>
          <div style={{ flex:1, textAlign:'center' }}>
            <div style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontWeight:800, fontSize:14,
              color:'white', letterSpacing:0.5 }}>{title}</div>
            <div style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontSize:11, color:'rgba(255,255,255,0.55)' }}>
              {onTerminal ? 'End of feed' : `${idx+1} / ${total}`}
            </div>
          </div>
          {/* Share button — hidden on terminal (nothing item-specific to share) */}
          {!onTerminal ? (
            <button onClick={()=>setShowShareSheet(true)} style={{ width:38,height:38,
              borderRadius:'50%',background:'rgba(0,0,0,0.55)',
              border:'1.5px solid rgba(255,255,255,0.22)',
              color:'white',cursor:'pointer',flexShrink:0,
              display:'flex',alignItems:'center',justifyContent:'center' }}>
              <svg width={17} height={17} viewBox="0 0 24 24" fill="none"
                stroke="white" strokeWidth={2.2} strokeLinecap="round">
                <circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/>
                <line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/>
                <line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/>
              </svg>
            </button>
          ) : (
            <div style={{ width:38, height:38, flexShrink:0 }}/>
          )}
        </div>
      </div>

      {/* ── SWIPE CONTAINER — Phase-6 drag-with-peek ── */}
      <div
        ref={containerRef}
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
        onTouchCancel={onTouchEnd}
        style={{ flex:1, position:'relative', overflow:'hidden', touchAction:'pan-y' }}>
        {containerH > 0 && (
          <>
            {/* PREV item — peeks from the top as user drags down. Base
                position above viewport; transform applies the live drag.
                When on terminal, prev is the last real item (feedItems[idx-1]
                resolves correctly via natural indexing). */}
            {idx > 0 && (
              <div
                style={{
                  position:'absolute',
                  left:0, right:0, top: -containerH,
                  height: containerH,
                  transform: `translateY(${dragOffset}px)`,
                  transition: isSnapping ? `transform ${snapDur}ms ${SNAP_CURVE}` : 'none',
                  willChange:'transform',
                }}>
                <FeedItem
                  item={feedItems[idx-1]}
                  isActive={false}
                  onShare={()=>setShowShareSheet(true)}
                />
              </div>
            )}

            {/* CURRENT item — follows the finger directly. Swaps to the
                TerminalContinuationCard when onTerminal. */}
            <div
              style={{
                position:'absolute',
                left:0, right:0, top:0,
                height: containerH,
                transform: `translateY(${dragOffset}px)`,
                transition: isSnapping ? `transform ${snapDur}ms ${SNAP_CURVE}` : 'none',
                willChange:'transform',
              }}>
              {onTerminal ? (
                <TerminalContinuationCard type={type} title={title}/>
              ) : (
                <FeedItem
                  item={cur}
                  isActive={!isSnapping && dragOffset === 0}
                  onShare={()=>setShowShareSheet(true)}
                />
              )}
            </div>

            {/* NEXT item — peeks from the bottom as user drags up. When the
                next position IS the terminal (only on shorts, idx === last
                real), render the TerminalContinuationCard as the peek. */}
            {idx < lastNavIdx && (
              <div
                style={{
                  position:'absolute',
                  left:0, right:0, top: containerH,
                  height: containerH,
                  transform: `translateY(${dragOffset}px)`,
                  transition: isSnapping ? `transform ${snapDur}ms ${SNAP_CURVE}` : 'none',
                  willChange:'transform',
                }}>
                {hasTerminal && (idx + 1) === TERMINAL_IDX ? (
                  <TerminalContinuationCard type={type} title={title}/>
                ) : (
                  <FeedItem
                    item={feedItems[idx+1]}
                    isActive={false}
                    onShare={()=>setShowShareSheet(true)}
                  />
                )}
              </div>
            )}
          </>
        )}
      </div>

      {/* ── SHARE SHEET ── */}
      {showShareSheet && (
        <div onClick={()=>setShowShareSheet(false)}
          style={{ position:'absolute', inset:0, zIndex:50,
            background:'rgba(0,0,0,0.65)',
            display:'flex', flexDirection:'column', justifyContent:'flex-end' }}>
          <div onClick={e=>e.stopPropagation()}
            style={{ background:'#111', borderRadius:'22px 22px 0 0',
              padding:'12px 0 40px',
              boxShadow:'0 -6px 40px rgba(0,0,0,0.5)' }}>
            <div style={{ width:38,height:4,background:'rgba(255,255,255,0.18)',
              borderRadius:2,margin:'0 auto 16px' }}/>
            <div style={{ textAlign:'center', marginBottom:22,
              fontFamily:"'Barlow Condensed',sans-serif",
              fontWeight:800, fontSize:16, color:'white', letterSpacing:0.5 }}>
              Share this Story
            </div>
            <div style={{ display:'flex', flexWrap:'wrap',
              justifyContent:'center', gap:16, padding:'0 20px' }}>
              {SHARE_PLATFORMS.map(p=>(
                <div key={p.label}
                  onClick={()=>{ p.action(); setShowShareSheet(false); }}
                  style={{ display:'flex', flexDirection:'column',
                    alignItems:'center', gap:6, cursor:'pointer', width:68 }}>
                  <div style={{ width:56,height:56,borderRadius:18,
                    background:p.bg, border:`1.5px solid ${p.color}44`,
                    display:'flex', alignItems:'center', justifyContent:'center',
                    boxShadow:`0 2px 14px ${p.color}22` }}>
                    {p.icon}
                  </div>
                  <span style={{ fontFamily:"'Barlow',sans-serif", fontSize:10,
                    color:'rgba(255,255,255,0.65)', fontWeight:600,
                    textAlign:'center' }}>{p.label}</span>
                </div>
              ))}
            </div>
            <button onClick={()=>setShowShareSheet(false)}
              style={{ display:'block', margin:'22px auto 0',
                background:'rgba(255,255,255,0.07)',
                border:'1px solid rgba(255,255,255,0.14)',
                borderRadius:14, padding:'12px 48px',
                fontFamily:"'Barlow Condensed',sans-serif",
                fontWeight:700, fontSize:15,
                color:'rgba(255,255,255,0.5)', cursor:'pointer' }}>
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}


// ════════════════════════════════════════════════════════════════
// UNIFIED VERTICAL FEED — Used by all 4 categories
// Shorts · Classifieds · Bulletins · District/State/National News
// ════════════════════════════════════════════════════════════════

// ── Normalise any data source into a common FeedItem shape ──────
function normaliseFeedItems(items, type) {
  return items.map((item, i) => {
    const base = {
      id:        item.id || item.ytId || i,
      type,
      likes:     Math.floor(Math.random()*980)+20,
      dislikes:  Math.floor(Math.random()*60)+2,
      comments:  Math.floor(Math.random()*120)+5,
      rating:    (3.5 + Math.random()*1.5).toFixed(1),
      uploadedAt: item.uploadedAt || item.time || new Date().toISOString(),
    };
    if (type === 'shorts') return {
      ...base,
      headline:   item.titleTe,
      headlineEn: item.titleEn,
      videoId:    item.ytId,
      thumbnail:  item.img,
      fullText:   item.titleTe + '\n\n' + item.titleEn,
      reporter:   item.channel,
      location:   'కర్నూలు జిల్లా',
      category:   'Shorts',
      date:       item.time || 'ఈరోజు',
      views:      item.views,
    };
    if (type === 'classifieds') return {
      ...base,
      headline:   item.title,
      headlineEn: item.title,
      videoId:    null,
      thumbnail:  item.img || CL_CAT_IMG[item.cat],
      fullText:   item.desc || item.title,
      reporter:   item.poster || 'స్థానిక వ్యాపారి',
      location:   item.location,
      category:   item.cat,
      date:       item.time,
      contact:    item.contact,
      price:      item.price,
    };
    if (type === 'bulletins') return {
      ...base,
      headline:   item.titleTe || item.channel + ' వార్తా బులెటిన్',
      headlineEn: item.titleEn || 'News Bulletin',
      videoId:    item.ytId,
      thumbnail:  `https://img.youtube.com/vi/${item.ytId}/hqdefault.jpg`,
      fullText:   'ఈరోజు ' + (item.channel||'కర్నూలు') + ' TV ప్రసారం. '
                + 'ముఖ్యమైన వార్తలు, స్థానిక సమాచారం మరియు ప్రత్యేక కార్యక్రమాలు '
                + (item.broadcastTime||'') + ' సమయంలో ప్రసారమయ్యాయి.',
      reporter:   item.channel,
      location:   'కర్నూలు',
      category:   'Bulletin',
      date:       item.broadcastTime || 'ఈరోజు',
    };
    // news (district/state/national/etc)
    return {
      ...base,
      headline:   item.titleTe || item.title,
      headlineEn: item.titleEn || item.title,
      videoId:    item.ytId || null,
      thumbnail:  item.thumbnail || CL_CAT_IMG[item.cat] ||
                  'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=400&q=75',
      fullText:   item.body || item.titleTe || item.title,
      reporter:   item.reporter || item.channel || 'LocalAI TV',
      location:   item.location || item.district || 'కర్నూలు జిల్లా',
      category:   item.cat || 'District',
      date:       item.time || 'ఈరోజు',
      views:      item.views,
    };
  });
}

// ── Comment Drawer ───────────────────────────────────────────────

// ════════════════════════════════════════════════════════════════
// KURNOOL SHORTS — Never-ending vertical swipe feed
// Sakshi/YouTube Shorts style. Finger swipe only. No arrows.
// Auto-plays video+audio. Full text inline. Reporter details.
// Feed order: today newest first → yesterday → older → loops back
// ════════════════════════════════════════════════════════════════

// ── Sort shorts: today first (latest time), then yesterday, loop ──
function sortShortsForFeed(items) {
  const sorted = [...items].sort((a, b) => {
    const da = a.uploadedAt ? new Date(a.uploadedAt) : new Date(0);
    const db = b.uploadedAt ? new Date(b.uploadedAt) : new Date(0);
    return db - da; // newest first
  });
  return sorted;
}

// ── Never-ending index: wraps around when all items shown ──
function getLoopIdx(rawIdx, total) {
  return ((rawIdx % total) + total) % total;
}

// ── Single Short Item ────────────────────────────────────────────
function KurnoolShortItem({ item, isActive, onShare, onBell }) {
  const { T } = useAppTheme();
  const [liked,      setLiked]      = useState(false);
  const [disliked,   setDisliked]   = useState(false);
  const [likeCount,  setLikeCount]  = useState(
    () => Math.floor(Math.random() * 300) + 20
  );
  const [showComment,  setShowComment]  = useState(false);
  const [showRating,   setShowRating]   = useState(false);
  const [showHeart,    setShowHeart]    = useState(false);
  const [bellActive,   setBellActive]   = useState(false);
  const [commentText,  setCommentText]  = useState('');
  const [ratingVal,    setRatingVal]    = useState(0);
  const [ratingDone,   setRatingDone]   = useState(false);
  // Orientation comes from the explicit `item.orientation` field
  // ('vertical' | 'horizontal'). YouTube's thumbnail dimensions are
  // unreliable (all returned as 1280×720 — even for vertical Shorts),
  // so we don't probe them. The data file tags each video correctly.
  const isVertical = item.orientation === 'vertical';
  const lastTap = useRef(0);

  // Refs for the YouTube iframe + tap-tracking on the gesture overlay
  const videoIframeRef = useRef(null);
  const tapStart = useRef(null);
  const [isPlaying, setIsPlaying] = useState(true);

  // Toggle YouTube play/pause via the IFrame API (requires enablejsapi=1 in src)
  const togglePlayPause = () => {
    if (!videoIframeRef.current) return;
    const cmd = isPlaying ? 'pauseVideo' : 'playVideo';
    try {
      videoIframeRef.current.contentWindow.postMessage(
        JSON.stringify({ event:'command', func:cmd, args:'' }), '*');
      setIsPlaying(p => !p);
    } catch(e) { /* ignore */ }
  };

  // Reset playing flag whenever the active item changes
  useEffect(() => { setIsPlaying(true); }, [item.id]);

  // Reset state when item changes
  useEffect(() => {
    setLiked(false);
    setDisliked(false);
    setShowComment(false);
    setShowRating(false);
    setRatingDone(false);
    setRatingVal(0);
  }, [item.id]);

  const handleLike = () => {
    if (!liked) { setLiked(true); setDisliked(false); setLikeCount(c => c + 1); }
    else         { setLiked(false); setLikeCount(c => c - 1); }
  };
  const handleDislike = () => {
    if (!disliked) { setDisliked(true); setLiked(false); setLikeCount(c => liked ? c - 1 : c); }
    else            { setDisliked(false); }
  };
  const handleDoubleTap = () => {
    const now = Date.now();
    if (now - lastTap.current < 320) {
      setLiked(true);
      setLikeCount(c => c + 1);
      setShowHeart(true);
      setTimeout(() => setShowHeart(false), 750);
    }
    lastTap.current = now;
  };

  // Format upload date/time nicely
  const formatUploadTime = () => {
    if (!item.uploadedAt) return item.uploadTime || '';
    const d   = new Date(item.uploadedAt);
    const now = new Date();
    const diffMs  = now - d;
    const diffMin = Math.floor(diffMs / 60000);
    const diffHr  = Math.floor(diffMs / 3600000);
    const diffDay = Math.floor(diffMs / 86400000);
    if (diffMin < 60)  return `${diffMin}m ago`;
    if (diffHr  < 24)  return `${diffHr}h ago`;
    if (diffDay === 1) return 'Yesterday ' + d.toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit'});
    return d.toLocaleDateString('en-IN', {day:'numeric', month:'short'}) + ' ' +
           d.toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit'});
  };

  const MOCK_COMMENTS = [
    { user:'రాజు', time:'2m', text:'చాలా మంచి వార్త! 👏', likes:12 },
    { user:'Priya', time:'8m', text:'LocalAI TV best channel!', likes:8 },
    { user:'వెంకట్', time:'15m', text:'ఇది చాలా అవసరమైన సమాచారం', likes:19 },
    { user:'Suresh', time:'22m', text:'Keep up the good work! 🙏', likes:5 },
    { user:'అనిత', time:'30m', text:'మీ వార్తలు చాలా నమ్మకంగా ఉంటాయి', likes:24 },
  ];

  return (
    <div style={{ width:'100%', height:'100%', display:'flex',
      flexDirection:'column', background:'#000', position:'relative',
      overflow:'hidden' }}>

      {/* ── Double-tap heart ── */}
      {showHeart && (
        <div style={{ position:'absolute', top:'30%', left:'50%', zIndex:50,
          transform:'translate(-50%,-50%)',
          fontSize:88, pointerEvents:'none',
          animation:'heartPop 0.7s ease forwards' }}>❤️</div>
      )}

      {/* Headline relocated below the video per user request — see scrollable area */}

      {/* ══ 1. VIDEO — orientation-aware sizing:
                vertical (Shorts / portrait) → 80%   horizontal (landscape) → 40% ══ */}
      <div onTouchStart={handleDoubleTap}
        style={{ height: isVertical ? '80%' : '40%',
          flexShrink:0, position:'relative',
          background:'#000', overflow:'hidden',
          transition:'height 0.25s ease' }}>
        {isActive && item.ytId ? (
          <>
            <iframe
              key={`v-${item.id}`}
              ref={el => { if (el) videoIframeRef.current = el; }}
              src={`https://www.youtube.com/embed/${item.ytId}?autoplay=1&mute=0&loop=1&playlist=${item.ytId}&controls=0&rel=0&modestbranding=1&enablejsapi=1&iv_load_policy=3&disablekb=1&showinfo=0&fs=0`}
              title={item.titleEn || item.titleTe}
              allow="autoplay; encrypted-media; fullscreen; picture-in-picture"
              allowFullScreen
              style={{ width:'100%', height:'100%', border:'none', display:'block' }}
            />
            {/* Gesture + tap-to-pause overlay. Catches swipe / wheel events (which the
                iframe would otherwise eat) AND treats a still tap as a play/pause toggle
                via the YouTube IFrame API postMessage. Bottom 48px left uncovered so
                YouTube's seek bar / fullscreen controls still work. */}
            <div
              onTouchStart={e => {
                tapStart.current = {
                  x: e.touches[0].clientX,
                  y: e.touches[0].clientY,
                  t: Date.now(),
                };
                handleDoubleTap();
              }}
              onTouchEnd={e => {
                const s = tapStart.current;
                if (!s) return;
                const t = e.changedTouches[0];
                const dx = Math.abs(t.clientX - s.x);
                const dy = Math.abs(t.clientY - s.y);
                const dt = Date.now() - s.t;
                // Treat short, still touches as a tap → toggle play/pause
                if (dx < 8 && dy < 8 && dt < 300) togglePlayPause();
                tapStart.current = null;
              }}
              onClick={e => {
                // Desktop click → toggle play/pause
                togglePlayPause();
              }}
              style={{position:'absolute', top:0, left:0, right:0, bottom:48,
                zIndex:3, background:'transparent', cursor:'pointer'}}/>
          </>
        ) : (
          <div style={{ width:'100%', height:'100%', position:'relative',
            cursor:'pointer' }}>
            <img
              src={item.img || `https://img.youtube.com/vi/${item.ytId}/maxresdefault.jpg`}
              alt={item.titleEn}
              style={{ width:'100%', height:'100%', objectFit:'cover' }}
              onError={e => { e.target.src = `https://img.youtube.com/vi/${item.ytId}/hqdefault.jpg`; }}
            />
            {/* Play icon */}
            <div style={{ position:'absolute', inset:0,
              display:'flex', alignItems:'center', justifyContent:'center',
              background:'rgba(0,0,0,0.25)' }}>
              <div style={{ width:52, height:52, borderRadius:'50%',
                background:'rgba(255,255,255,0.92)',
                display:'flex', alignItems:'center', justifyContent:'center',
                boxShadow:'0 4px 20px rgba(0,0,0,0.5)' }}>
                <div style={{ width:0, height:0, marginLeft:5,
                  borderTop:'13px solid transparent',
                  borderBottom:'13px solid transparent',
                  borderLeft:'21px solid #D0021B' }}/>
              </div>
            </div>
          </div>
        )}
        {/* ── LocalAI TV channel watermark — top-right of the video.
              Offsets bumped 8 → 18 (top) / 8 → 16 (right) so it doesn't hug the edges. ── */}
        <div style={{ position:'absolute', top:18, right:16, zIndex:6,
          background:'rgba(0,0,0,0.5)', borderRadius:6, padding:'2px 6px',
          pointerEvents:'none', backdropFilter:'blur(2px)' }}>
          <Logo size="xs" dark={true} showTV={true}/>
        </div>

        {/* LIVE badge */}
        {item.live && (
          <div style={{ position:'absolute', bottom:10, left:12,
            display:'flex', alignItems:'center', gap:4,
            background:'#D0021B', borderRadius:6, padding:'4px 10px',
            boxShadow:'0 2px 10px rgba(208,2,27,0.5)', zIndex:5 }}>
            <div style={{ width:6, height:6, borderRadius:'50%',
              background:'white', animation:'blink 1s infinite' }}/>
            <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontWeight:900, fontSize:11, color:'white', letterSpacing:1.2 }}>LIVE</span>
          </div>
        )}
        {/* Duration */}
        {!item.live && item.duration && (
          <div style={{ position:'absolute', bottom:10, right:12,
            background:'rgba(0,0,0,0.75)', borderRadius:5,
            padding:'3px 8px', zIndex:5 }}>
            <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontSize:11, fontWeight:700, color:'white' }}>▶ {item.duration}</span>
          </div>
        )}
        {/* Bottom fade */}
        <div style={{ position:'absolute', bottom:0, left:0, right:0, height:24,
          background:'linear-gradient(0deg,#000 0%,transparent 100%)',
          pointerEvents:'none' }}/>
      </div>

      {/* ══ SCROLLABLE CONTENT BELOW VIDEO ═════════════════════
            New order per user request:
              2. HEADLINE  →  3. DESCRIPTION  →  4. ACTION BAR  →  5. REPORTER … */}
      <div style={{ flex:1, overflowY:'auto', scrollbarWidth:'none',
        WebkitOverflowScrolling:'touch',
        display:'flex', flexDirection:'column',
        background:'linear-gradient(180deg,#000 0%,#050a14 100%)' }}>

        {/* ══ 2. HEADLINE — Telugu only (English subtitle removed per user request) ══ */}
        <div style={{ padding:'12px 16px 8px',
          borderBottom:'1px solid rgba(255,255,255,0.06)' }}>
          <h2 style={{ margin:0,
            fontFamily:"'Noto Sans Telugu',sans-serif",
            fontWeight:900, fontSize:18, lineHeight:1.4,
            color:'#fff' }}>
            {item.titleTe}
          </h2>
        </div>

        {/* ══ 3. DESCRIPTION — shown ONLY for HORIZONTAL videos (40% layout).
              Vertical Shorts (70% layout) skip this and go straight to uploader/actions. */}
        {!isVertical && (
          <div style={{ padding:'14px 16px 10px',
            borderBottom:'1px solid rgba(255,255,255,0.06)' }}>
            {item.category && (
              <div style={{ display:'inline-flex', alignItems:'center',
                background:'rgba(208,2,27,0.15)',
                border:'1px solid rgba(208,2,27,0.3)',
                borderRadius:6, padding:'3px 10px', marginBottom:10 }}>
                <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                  fontWeight:800, fontSize:11, color:'#FF3B30',
                  letterSpacing:0.5, textTransform:'uppercase' }}>
                  {item.category}
                </span>
              </div>
            )}
            <p style={{ margin:0,
              fontFamily:"'Noto Sans Telugu',sans-serif",
              fontSize:14, lineHeight:1.85,
              color:'rgba(255,255,255,0.85)',
              whiteSpace:'pre-wrap' }}>
              {item.fullText}
            </p>
          </div>
        )}

        {/* ══ 4. UPLOADER LINE — single row: Name · time · location ══════════ */}
        <div style={{
          display:'flex', alignItems:'center', gap:6,
          padding:'8px 16px',
          borderBottom:'1px solid rgba(255,255,255,0.06)',
          fontFamily:"'Barlow Condensed',sans-serif",
          fontSize:12, fontWeight:600,
          color:'rgba(255,255,255,0.72)',
          overflow:'hidden', whiteSpace:'nowrap',
        }}>
          <span style={{
            color:'rgba(255,255,255,0.95)', fontWeight:800,
            overflow:'hidden', textOverflow:'ellipsis', maxWidth:'40%',
          }}>
            👤 {item.reporter || item.channel || 'LocalAI TV'}
          </span>
          {formatUploadTime() && (
            <>
              <span style={{color:'rgba(255,255,255,0.25)'}}>·</span>
              <span style={{color:'rgba(255,255,255,0.6)'}}>🕐 {formatUploadTime()}</span>
            </>
          )}
          {item.location && (
            <>
              <span style={{color:'rgba(255,255,255,0.25)'}}>·</span>
              <span style={{
                color:'rgba(255,255,255,0.6)',
                overflow:'hidden', textOverflow:'ellipsis', flex:1, minWidth:0,
              }}>📍 {item.location}</span>
            </>
          )}
        </div>

        {/* ══ 5. ACTION BAR — 5 buttons: Like · Dislike · Comment · Views · Share ════ */}
        <div style={{ display:'flex', alignItems:'center', gap:4,
          padding:'10px 14px 10px',
          borderBottom:'1px solid rgba(255,255,255,0.08)' }}>

          {/* 1. Like — YouTube-style thumbs-up SVG (outline inactive, filled active) — hover: lift + blue glow */}
          <button onClick={handleLike}
            onMouseEnter={e=>{
              e.currentTarget.style.transform='translateY(-2px) scale(1.04)';
              e.currentTarget.style.boxShadow='0 4px 14px rgba(59,143,255,0.45)';
              e.currentTarget.style.borderColor='rgba(59,143,255,0.55)';
              e.currentTarget.style.background='rgba(59,143,255,0.18)';
            }}
            onMouseLeave={e=>{
              e.currentTarget.style.transform='translateY(0) scale(1)';
              e.currentTarget.style.boxShadow='none';
              e.currentTarget.style.borderColor= liked ? 'rgba(59,143,255,0.5)' : 'rgba(255,255,255,0.1)';
              e.currentTarget.style.background= liked ? 'rgba(59,143,255,0.18)' : 'rgba(255,255,255,0.07)';
            }}
            style={{
            flex:1, display:'flex', flexDirection:'column',
            alignItems:'center', gap:3,
            background: liked ? 'rgba(59,143,255,0.18)' : 'rgba(255,255,255,0.07)',
            border: `1px solid ${liked ? 'rgba(59,143,255,0.5)' : 'rgba(255,255,255,0.1)'}`,
            borderRadius:11, padding:'8px 4px',
            cursor:'pointer', transition:'all 0.18s cubic-bezier(0.22,1,0.36,1)' }}>
            <svg width={20} height={20} viewBox="0 0 24 24"
              fill={liked ? '#3B8FFF' : 'none'}
              stroke={liked ? '#3B8FFF' : 'rgba(255,255,255,0.8)'}
              strokeWidth={2} strokeLinecap="round" strokeLinejoin="round"
              style={{ transform: liked ? 'scale(1.12)' : 'scale(1)', transition:'transform 0.18s' }}>
              <path d="M7 10v12"/>
              <path d="M15 5.88 14 12h5.5a2 2 0 0 1 2 2.26l-1.1 7A2 2 0 0 1 18.44 23H7a4 4 0 0 1-4-4v-7a4 4 0 0 1 4-4h2.83a2 2 0 0 0 1.92-1.45l1.9-6.55A.9.9 0 0 1 14.74 0 2.26 2.26 0 0 1 17 2.26V5.88Z"/>
            </svg>
            <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontSize:9, fontWeight:800, letterSpacing:0.3,
              color: liked ? '#3B8FFF' : 'rgba(255,255,255,0.6)' }}>
              {likeCount}
            </span>
          </button>

          {/* 2. Dislike — YouTube-style thumbs-down SVG (outline inactive, filled active) — hover: lift + orange glow */}
          <button onClick={handleDislike}
            onMouseEnter={e=>{
              e.currentTarget.style.transform='translateY(-2px) scale(1.04)';
              e.currentTarget.style.boxShadow='0 4px 14px rgba(255,149,0,0.45)';
              e.currentTarget.style.borderColor='rgba(255,149,0,0.55)';
              e.currentTarget.style.background='rgba(255,149,0,0.18)';
            }}
            onMouseLeave={e=>{
              e.currentTarget.style.transform='translateY(0) scale(1)';
              e.currentTarget.style.boxShadow='none';
              e.currentTarget.style.borderColor= disliked ? 'rgba(255,149,0,0.5)' : 'rgba(255,255,255,0.1)';
              e.currentTarget.style.background= disliked ? 'rgba(255,149,0,0.18)' : 'rgba(255,255,255,0.07)';
            }}
            style={{
            flex:1, display:'flex', flexDirection:'column',
            alignItems:'center', gap:3,
            background: disliked ? 'rgba(255,149,0,0.18)' : 'rgba(255,255,255,0.07)',
            border: `1px solid ${disliked ? 'rgba(255,149,0,0.5)' : 'rgba(255,255,255,0.1)'}`,
            borderRadius:11, padding:'8px 4px',
            cursor:'pointer', transition:'all 0.18s cubic-bezier(0.22,1,0.36,1)' }}>
            <svg width={20} height={20} viewBox="0 0 24 24"
              fill={disliked ? '#FF9500' : 'none'}
              stroke={disliked ? '#FF9500' : 'rgba(255,255,255,0.8)'}
              strokeWidth={2} strokeLinecap="round" strokeLinejoin="round"
              style={{ transform: disliked ? 'scale(1.12)' : 'scale(1)', transition:'transform 0.18s' }}>
              <path d="M17 14V2"/>
              <path d="M9 18.12 10 12H4.5a2 2 0 0 1-2-2.26l1.1-7A2 2 0 0 1 5.56 1H17a4 4 0 0 1 4 4v7a4 4 0 0 1-4 4h-2.83a2 2 0 0 0-1.92 1.45l-1.9 6.55A.9.9 0 0 1 9.26 24 2.26 2.26 0 0 1 7 21.74V18.12Z"/>
            </svg>
            <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontSize:9, fontWeight:800, letterSpacing:0.3,
              color: disliked ? '#FF9500' : 'rgba(255,255,255,0.5)' }}>Dislike</span>
          </button>

          {/* 3. Comment — hover: lift + teal glow */}
          <button onClick={() => setShowComment(true)}
            onMouseEnter={e=>{
              e.currentTarget.style.transform='translateY(-2px) scale(1.04)';
              e.currentTarget.style.boxShadow='0 4px 14px rgba(0,200,184,0.45)';
              e.currentTarget.style.borderColor='rgba(0,200,184,0.55)';
              e.currentTarget.style.background='rgba(0,200,184,0.18)';
            }}
            onMouseLeave={e=>{
              e.currentTarget.style.transform='translateY(0) scale(1)';
              e.currentTarget.style.boxShadow='none';
              e.currentTarget.style.borderColor='rgba(255,255,255,0.1)';
              e.currentTarget.style.background='rgba(255,255,255,0.07)';
            }}
            style={{
            flex:1, display:'flex', flexDirection:'column',
            alignItems:'center', gap:3,
            background:'rgba(255,255,255,0.07)',
            border:'1px solid rgba(255,255,255,0.1)',
            borderRadius:11, padding:'8px 4px', cursor:'pointer',
            transition:'all 0.18s cubic-bezier(0.22,1,0.36,1)' }}>
            <span style={{ fontSize:19 }}>💬</span>
            <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontSize:9, fontWeight:800, letterSpacing:0.3,
              color:'rgba(255,255,255,0.45)' }}>Comment</span>
          </button>

          {/* 4. Views — non-interactive display of how many people have watched — hover: lift + violet glow */}
          <div
            onMouseEnter={e=>{
              e.currentTarget.style.transform='translateY(-2px) scale(1.04)';
              e.currentTarget.style.boxShadow='0 4px 14px rgba(123,31,162,0.45)';
              e.currentTarget.style.borderColor='rgba(123,31,162,0.55)';
              e.currentTarget.style.background='rgba(123,31,162,0.18)';
            }}
            onMouseLeave={e=>{
              e.currentTarget.style.transform='translateY(0) scale(1)';
              e.currentTarget.style.boxShadow='none';
              e.currentTarget.style.borderColor='rgba(255,255,255,0.1)';
              e.currentTarget.style.background='rgba(255,255,255,0.07)';
            }}
            style={{
            flex:1, display:'flex', flexDirection:'column',
            alignItems:'center', gap:3,
            background:'rgba(255,255,255,0.07)',
            border:'1px solid rgba(255,255,255,0.1)',
            borderRadius:11, padding:'8px 4px',
            userSelect:'none',
            transition:'all 0.18s cubic-bezier(0.22,1,0.36,1)' }}>
            <span style={{ fontSize:19 }}>👁</span>
            <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontSize:9, fontWeight:800, letterSpacing:0.3,
              color:'rgba(255,255,255,0.7)' }}>
              {item.views || '0'}
            </span>
          </div>

          {/* 5. Share — hover: lift + gold glow */}
          <button onClick={onShare}
            onMouseEnter={e=>{
              e.currentTarget.style.transform='translateY(-2px) scale(1.04)';
              e.currentTarget.style.boxShadow='0 4px 14px rgba(255,184,0,0.5)';
              e.currentTarget.style.borderColor='rgba(255,184,0,0.55)';
              e.currentTarget.style.background='rgba(255,184,0,0.18)';
            }}
            onMouseLeave={e=>{
              e.currentTarget.style.transform='translateY(0) scale(1)';
              e.currentTarget.style.boxShadow='none';
              e.currentTarget.style.borderColor='rgba(255,255,255,0.1)';
              e.currentTarget.style.background='rgba(255,255,255,0.07)';
            }}
            style={{
            flex:1, display:'flex', flexDirection:'column',
            alignItems:'center', gap:3,
            background:'rgba(255,255,255,0.07)',
            border:'1px solid rgba(255,255,255,0.1)',
            borderRadius:11, padding:'8px 4px', cursor:'pointer',
            transition:'all 0.18s cubic-bezier(0.22,1,0.36,1)' }}>
            <svg width={20} height={20} viewBox="0 0 24 24" fill="none"
              stroke="rgba(255,255,255,0.7)" strokeWidth={2.2} strokeLinecap="round">
              <circle cx="18" cy="5" r="3"/>
              <circle cx="6" cy="12" r="3"/>
              <circle cx="18" cy="19" r="3"/>
              <line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/>
              <line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/>
            </svg>
            <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
              fontSize:9, fontWeight:800, letterSpacing:0.3,
              color:'rgba(255,255,255,0.45)' }}>Share</span>
          </button>
        </div>

        {/* Verbose reporter / metadata card removed — replaced by single-line uploader strip above */}

        {/* Swipe hint */}
        <div style={{ textAlign:'center', padding:'2px 0 18px' }}>
          <span style={{ fontSize:10,
            color:'rgba(255,255,255,0.18)',
            fontFamily:"'Barlow',sans-serif",
            letterSpacing:0.4 }}>↑ swipe up for next short</span>
        </div>
      </div>

      {/* ══ COMMENT DRAWER ══════════════════════════════════════ */}
      {showComment && (
        <div onClick={() => setShowComment(false)}
          style={{ position:'absolute', inset:0, zIndex:60,
            background:'rgba(0,0,0,0.6)',
            display:'flex', flexDirection:'column', justifyContent:'flex-end' }}>
          <div onClick={e => e.stopPropagation()}
            style={{ background:'#111', borderRadius:'20px 20px 0 0',
              maxHeight:'65%', display:'flex', flexDirection:'column',
              boxShadow:'0 -8px 40px rgba(0,0,0,0.5)' }}>
            <div style={{ display:'flex', alignItems:'center',
              justifyContent:'space-between',
              padding:'14px 18px 10px',
              borderBottom:'1px solid rgba(255,255,255,0.08)' }}>
              <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                fontWeight:800, fontSize:16, color:'white' }}>
                💬 Comments (5)
              </span>
              <button onClick={() => setShowComment(false)}
                style={{ background:'none', border:'none',
                  fontSize:20, color:'rgba(255,255,255,0.5)', cursor:'pointer' }}>✕</button>
            </div>
            <div style={{ flex:1, overflowY:'auto', padding:'12px 18px',
              display:'flex', flexDirection:'column', gap:14 }}>
              {MOCK_COMMENTS.map((c, i) => (
                <div key={i} style={{ display:'flex', gap:10 }}>
                  <div style={{ width:34, height:34, borderRadius:'50%',
                    flexShrink:0, fontSize:14, fontWeight:800, color:'white',
                    background:'linear-gradient(135deg,#D0021B,#FF6B00)',
                    display:'flex', alignItems:'center', justifyContent:'center' }}>
                    {c.user[0]}
                  </div>
                  <div style={{ flex:1 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:3 }}>
                      <span style={{ fontFamily:"'Barlow Condensed',sans-serif",
                        fontWeight:700, fontSize:13, color:'white' }}>{c.user}</span>
                      <span style={{ fontSize:10, color:'rgba(255,255,255,0.35)' }}>{c.time}m</span>
                    </div>
                    <div style={{ fontFamily:"'Noto Sans Telugu',sans-serif",
                      fontSize:13, color:'rgba(255,255,255,0.8)', lineHeight:1.5 }}>{c.text}</div>
                    <div style={{ fontSize:10, color:'rgba(255,255,255,0.3)', marginTop:3 }}>
                      ❤️ {c.likes}
                    </div>
                  </div>
                </div>
              ))}
            </div>
            <div style={{ display:'flex', gap:8,
              padding:'10px 16px 24px',
              borderTop:'1px solid rgba(255,255,255,0.08)' }}>
              <input value={commentText}
                onChange={e => setCommentText(e.target.value)}
                placeholder="మీ అభిప్రాయం రాయండి..."
                style={{ flex:1, background:'rgba(255,255,255,0.08)',
                  border:'1px solid rgba(255,255,255,0.15)',
                  borderRadius:22, padding:'10px 16px', fontSize:13,
                  fontFamily:"'Noto Sans Telugu',sans-serif",
                  color:'white', outline:'none' }}/>
              <button onClick={() => setCommentText('')}
                style={{ width:42, height:42, borderRadius:'50%',
                  background: commentText ? '#D0021B' : 'rgba(255,255,255,0.08)',
                  border:'none', cursor:'pointer', fontSize:18, color:'white',
                  display:'flex', alignItems:'center', justifyContent:'center',
                  transition:'background 0.2s' }}>⬆</button>
            </div>
          </div>
        </div>
      )}

      {/* ══ RATING DRAWER ════════════════════════════════════════ */}
      {showRating && (
        <div onClick={() => setShowRating(false)}
          style={{ position:'absolute', inset:0, zIndex:60,
            background:'rgba(0,0,0,0.6)',
            display:'flex', flexDirection:'column', justifyContent:'flex-end' }}>
          <div onClick={e => e.stopPropagation()}
            style={{ background:'#111', borderRadius:'20px 20px 0 0',
              padding:'20px 24px 40px', textAlign:'center',
              boxShadow:'0 -8px 40px rgba(0,0,0,0.5)' }}>
            <div style={{ width:36, height:4,
              background:'rgba(255,255,255,0.2)',
              borderRadius:2, margin:'0 auto 16px' }}/>
            {ratingDone ? (
              <>
                <div style={{ fontSize:50, marginBottom:12 }}>🙏</div>
                <div style={{ fontFamily:"'Noto Sans Telugu',sans-serif",
                  fontSize:16, fontWeight:800, color:'white', marginBottom:4 }}>
                  ధన్యవాదాలు!
                </div>
                <div style={{ fontSize:13, color:'rgba(255,255,255,0.5)' }}>
                  మీ రేటింగ్ నమోదు అయింది • {ratingVal} ⭐
                </div>
              </>
            ) : (
              <>
                <div style={{ fontFamily:"'Noto Sans Telugu',sans-serif",
                  fontWeight:800, fontSize:17, color:'white', marginBottom:4 }}>
                  ఈ వార్తను రేట్ చేయండి
                </div>
                <div style={{ fontSize:12, color:'rgba(255,255,255,0.4)',
                  marginBottom:22 }}>Rate this news</div>
                <div style={{ display:'flex', justifyContent:'center',
                  gap:10, marginBottom:24 }}>
                  {[1,2,3,4,5].map(star => (
                    <button key={star} onClick={() => setRatingVal(star)}
                      style={{ fontSize:36, background:'none', border:'none',
                        cursor:'pointer', transition:'transform 0.15s',
                        transform: star <= ratingVal ? 'scale(1.2)' : 'scale(1)',
                        filter: star <= ratingVal ? 'none' : 'grayscale(1) opacity(0.35)' }}>⭐</button>
                  ))}
                </div>
                <button
                  onClick={() => { if (ratingVal) { setRatingDone(true); setTimeout(() => setShowRating(false), 1600); }}}
                  disabled={!ratingVal}
                  style={{ width:'100%', padding:'14px',
                    background: ratingVal ? '#D0021B' : 'rgba(255,255,255,0.08)',
                    color: ratingVal ? 'white' : 'rgba(255,255,255,0.3)',
                    border:'none', borderRadius:14,
                    fontFamily:"'Barlow Condensed',sans-serif",
                    fontWeight:900, fontSize:16, letterSpacing:0.5,
                    cursor: ratingVal ? 'pointer' : 'default',
                    transition:'all 0.2s' }}>
                  Submit Rating
                </button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ── Share Sheet for Shorts ───────────────────────────────────────
function ShortsShareSheet({ item, onClose }) {
  const enc  = encodeURIComponent;
  const text = enc(`${item.titleTe}\n${item.titleEn || ''}\n📱 LocalAI TV: https://localaitv.com/app`);
  const url  = enc('https://localaitv.com/app');

  const PLATFORMS = [
    { label:'WhatsApp',  color:'#25D366', bg:'rgba(37,211,102,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="#25D366"><path d="M16 2C8.28 2 2 8.28 2 16c0 2.46.67 4.76 1.83 6.74L2 30l7.44-1.79A13.94 13.94 0 0016 30c7.72 0 14-6.28 14-14S23.72 2 16 2zm7.1 19.1c-.3.84-1.76 1.6-2.4 1.7-.62.1-1.4.14-2.26-.14a20.6 20.6 0 01-2.04-.75c-3.58-1.55-5.92-5.16-6.1-5.4-.18-.24-1.46-1.94-1.46-3.7s.92-2.62 1.26-2.98c.3-.34.66-.42.88-.42l.64.01c.2 0 .48-.08.74.56.28.66.94 2.3.02 2.56l-.5.22c-.28.14-.52.3-.36.6.16.3.7 1.16 1.5 1.88l1.44 1.14c.3.16.6.12.82-.12.22-.24.9-1.04 1.14-1.4.24-.36.48-.3.8-.18.32.12 2.02.96 2.36 1.13.34.18.58.26.66.4.08.16.08.9-.22 1.74z"/></svg>,
      action:()=>window.open(`https://api.whatsapp.com/send?text=${text}`,'_blank') },
    { label:'Telegram',  color:'#0088CC', bg:'rgba(0,136,204,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="#0088CC"><path d="M16 2C8.27 2 2 8.27 2 16s6.27 14 14 14 14-6.27 14-14S23.73 2 16 2zm6.84 9.58l-2.36 11.12c-.18.8-.64 1-1.3.62l-3.6-2.65-1.73 1.67c-.2.2-.36.36-.73.36l.26-3.68 6.7-6.05c.3-.26-.06-.4-.44-.14l-8.28 5.21-3.57-1.12c-.78-.24-.8-.78.16-1.15l13.93-5.37c.64-.24 1.2.14.96 1.18z"/></svg>,
      action:()=>window.open(`https://t.me/share/url?url=${url}&text=${text}`,'_blank') },
    { label:'Facebook',  color:'#1877F2', bg:'rgba(24,119,242,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="#1877F2"><path d="M16 2C8.27 2 2 8.27 2 16c0 6.99 5.12 12.77 11.81 13.82V19.9h-3.55V16h3.55v-3.08c0-3.51 2.09-5.44 5.28-5.44 1.53 0 3.12.27 3.12.27v3.44h-1.76c-1.73 0-2.27 1.07-2.27 2.17V16h3.87l-.62 3.9h-3.25v9.92C24.88 28.77 30 22.99 30 16c0-7.73-6.27-14-14-14z"/></svg>,
      action:()=>window.open(`https://www.facebook.com/sharer/sharer.php?u=${url}`,'_blank') },
    { label:'X/Twitter', color:'#fff',    bg:'rgba(255,255,255,0.1)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="white"><path d="M18.24 14.17L27.1 4h-2.1l-7.7 8.95L11 4H4l9.3 13.53L4 28h2.1l8.13-9.45L21 28h7z"/></svg>,
      action:()=>window.open(`https://twitter.com/intent/tweet?text=${text}`,'_blank') },
    { label:'Email',     color:'#EA4335', bg:'rgba(234,67,53,0.15)',
      icon:<svg width={26} height={26} viewBox="0 0 32 32" fill="none"><rect x="2" y="6" width="28" height="20" rx="3" stroke="#EA4335" strokeWidth="2.2"/><path d="M2 10l14 9 14-9" stroke="#EA4335" strokeWidth="2.2" strokeLinecap="round"/></svg>,
      action:()=>window.open(`mailto:?subject=${enc(item.titleEn||item.titleTe)}&body=${text}`,'_blank') },
    { label:'More',      color:'#9CA3AF', bg:'rgba(156,163,175,0.12)',
      icon:<svg width={26} height={26} viewBox="0 0 24 24" fill="none" stroke="#9CA3AF" strokeWidth={2.2} strokeLinecap="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>,
      action:()=>{ navigator.share ? navigator.share({title:item.titleEn||item.titleTe, text:decodeURIComponent(text), url:'https://localaitv.com/app'}).catch(()=>{}) : navigator.clipboard?.writeText(decodeURIComponent(text)); }},
  ];

  return (
    <div onClick={onClose}
      style={{ position:'absolute', inset:0, zIndex:70,
        background:'rgba(0,0,0,0.65)',
        display:'flex', flexDirection:'column', justifyContent:'flex-end' }}>
      <div onClick={e => e.stopPropagation()}
        style={{ background:'#111', borderRadius:'22px 22px 0 0',
          padding:'12px 0 42px',
          boxShadow:'0 -6px 40px rgba(0,0,0,0.6)' }}>
        <div style={{ width:38, height:4,
          background:'rgba(255,255,255,0.18)',
          borderRadius:2, margin:'0 auto 16px' }}/>
        <div style={{ textAlign:'center', marginBottom:22,
          fontFamily:"'Barlow Condensed',sans-serif",
          fontWeight:800, fontSize:16, color:'white', letterSpacing:0.5 }}>
          Share this Short
        </div>
        <div style={{ display:'flex', flexWrap:'wrap',
          justifyContent:'center', gap:16, padding:'0 20px' }}>
          {PLATFORMS.map(p => (
            <div key={p.label}
              onClick={() => { p.action(); onClose(); }}
              style={{ display:'flex', flexDirection:'column',
                alignItems:'center', gap:6, cursor:'pointer', width:68 }}>
              <div style={{ width:56, height:56, borderRadius:18,
                background:p.bg,
                border:`1.5px solid ${p.color}44`,
                display:'flex', alignItems:'center', justifyContent:'center',
                boxShadow:`0 2px 16px ${p.color}22` }}>
                {p.icon}
              </div>
              <span style={{ fontFamily:"'Barlow',sans-serif",
                fontSize:10, color:'rgba(255,255,255,0.65)',
                fontWeight:600, textAlign:'center' }}>{p.label}</span>
            </div>
          ))}
        </div>
        <button onClick={onClose}
          style={{ display:'block', margin:'22px auto 0',
            background:'rgba(255,255,255,0.07)',
            border:'1px solid rgba(255,255,255,0.14)',
            borderRadius:14, padding:'12px 50px',
            fontFamily:"'Barlow Condensed',sans-serif",
            fontWeight:700, fontSize:15,
            color:'rgba(255,255,255,0.5)', cursor:'pointer' }}>
          Cancel
        </button>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════
// MAIN: KurnoolShortsScreen
// Never-ending vertical swipe feed
// ════════════════════════════════════════════════════════════════
function KurnoolShortsScreen({ onClose, initialIdx = 0, rawItems }) {
  const { T }   = useAppTheme();
  // Sort by date/time: today first (latest), then yesterday, etc.
  const sorted  = useMemo(() => sortShortsForFeed(rawItems || SHORT_NEWS), [rawItems]);
  const total   = sorted.length;

  const [rawIdx,    setRawIdx]    = useState(initialIdx);
  const [animDir,   setAnimDir]   = useState(null); // 'up' | 'down'
  const [showShare, setShowShare] = useState(false);

  // Actual index with loop wrapping
  const idx = getLoopIdx(rawIdx, total);
  const cur = sorted[idx];

  const touchY  = useRef(0);
  const touchX  = useRef(0);
  const moved   = useRef(false);
  const animating = useRef(false);

  // Lock body scroll
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = ''; };
  }, []);

  // Keyboard nav
  useEffect(() => {
    const h = e => {
      if (e.key === 'ArrowUp')   goNext();
      if (e.key === 'ArrowDown') goPrev();
      if (e.key === 'Escape')    onClose();
    };
    window.addEventListener('keydown', h);
    return () => window.removeEventListener('keydown', h);
  }, [rawIdx]);

  const goNext = () => {
    if (animating.current) return;
    animating.current = true;
    setAnimDir('up');
    setTimeout(() => {
      setRawIdx(i => i + 1); // always increments, loops via getLoopIdx
      setAnimDir(null);
      animating.current = false;
    }, 270);
  };

  const goPrev = () => {
    if (animating.current) return;
    animating.current = true;
    setAnimDir('down');
    setTimeout(() => {
      // Decrement freely — getLoopIdx wraps negatives so the feed
      // loops 360° in BOTH directions (newest → oldest → newest …).
      setRawIdx(i => i - 1);
      setAnimDir(null);
      animating.current = false;
    }, 270);
  };

  const onTouchStart = e => {
    touchY.current = e.touches[0].clientY;
    touchX.current = e.touches[0].clientX;
    moved.current  = false;
  };
  const onTouchMove = e => { moved.current = true; };
  const onTouchEnd  = e => {
    if (!moved.current) return;
    const dy = touchY.current - e.changedTouches[0].clientY;
    const dx = Math.abs(e.changedTouches[0].clientX - touchX.current);
    if (dx > Math.abs(dy) * 0.8) return; // horizontal — ignore
    if (dy > 55)  goNext();
    if (dy < -55) goPrev();
  };

  // Mouse-wheel scroll → navigate (so desktop users get the same continuous
  // up/next, down/prev behaviour as touch users).
  // Throttled via `wheelLock` so a single trackpad flick only advances one short.
  const wheelLock = useRef(false);
  const onWheel = e => {
    if (wheelLock.current || animating.current) return;
    if (Math.abs(e.deltaY) < 18) return; // small noise → ignore
    wheelLock.current = true;
    if (e.deltaY > 0) goNext();
    else              goPrev();
    setTimeout(() => { wheelLock.current = false; }, 450);
  };

  // Date group label (Today / Yesterday / DD MMM)
  const getDateLabel = (item) => {
    if (!item.uploadedAt) return item.uploadDate || '';
    const d    = new Date(item.uploadedAt);
    const now  = new Date();
    const diff = Math.floor((now - d) / 86400000);
    if (diff === 0) return 'నేడు (Today)';
    if (diff === 1) return 'నిన్న (Yesterday)';
    return d.toLocaleDateString('en-IN', { day:'numeric', month:'short', year:'numeric' });
  };

  return (
    <div style={{ position:'fixed', inset:0, zIndex:300, background:'#000',
      display:'flex', flexDirection:'column', overflow:'hidden' }}>

      {/* Top progress bars removed per user request — cleaner top of video */}

      {/* Discreet back button only — title / index / date removed per user request.
          The LocalAI TV channel logo now sits in the top-right corner of the video itself. */}
      <button onClick={onClose}
        style={{ position:'absolute', top:18, left:14, zIndex:21,
          width:36, height:36, borderRadius:'50%',
          background:'rgba(0,0,0,0.55)',
          border:'1.5px solid rgba(255,255,255,0.22)',
          color:'white', fontSize:18, cursor:'pointer',
          display:'flex', alignItems:'center', justifyContent:'center',
          pointerEvents:'all' }}>←</button>

      {/* ── SWIPE + WHEEL CONTAINER ──
            Touch swipe and mouse wheel both navigate continuously between Shorts. */}
      <div
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
        onWheel={onWheel}
        style={{ flex:1, position:'relative', overflow:'hidden', paddingTop:0 }}>
        <div
          key={`short-${idx}`}
          style={{
            position:'absolute', inset:0, paddingTop:0,
            animation: animDir === 'up'
              ? 'slideOutUp 0.27s cubic-bezier(0.4,0,0.2,1) forwards'
              : animDir === 'down'
              ? 'slideOutDown 0.27s cubic-bezier(0.4,0,0.2,1) forwards'
              : 'slideInUp 0.29s cubic-bezier(0.4,0,0.2,1) both',
          }}>
          <KurnoolShortItem
            item={cur}
            isActive={!animDir}
            onShare={() => setShowShare(true)}
            onBell={() => {}}
          />
        </div>
      </div>

      {/* Share sheet */}
      {showShare && (
        <ShortsShareSheet item={cur} onClose={() => setShowShare(false)} />
      )}
    </div>
  );
}



