            <path d="M30 47.5 C27.5 47.5, 25.8 49.2, 25.8 51.4 C25.8 53.8, 30 57, 30 57 C30 57, 34.2 53.8, 34.2 51.4 C34.2 49.2, 32.5 47.5, 30 47.5 Z" fill="#D0021B"/>
